import React, { useState, useMemo } from 'react';
import { WellBeingLevel, Question, ResponseIndicator, StudentInfo, Submission } from '../types';
import { QUIZ_DATA } from '../constants';

interface QuizProps {
  onComplete: (submission: Submission) => void;
}

type QuizStep = 'level-select' | 'student-info' | 'questions' | 'completed';

const Quiz: React.FC<QuizProps> = ({ onComplete }) => {
  const [step, setStep] = useState<QuizStep>('level-select');
  const [selectedLevel, setSelectedLevel] = useState<WellBeingLevel | null>(null);
  const [studentInfo, setStudentInfo] = useState<StudentInfo>({ name: '', age: '', standard: '', school: '' });
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [answers, setAnswers] = useState<{ [id: string]: ResponseIndicator }>({});

  const filteredQuestions = useMemo(() => {
    return QUIZ_DATA.filter(q => q.level === selectedLevel);
  }, [selectedLevel]);

  const progress = filteredQuestions.length > 0 
    ? Math.round(((currentQuestionIndex) / filteredQuestions.length) * 100) 
    : 0;

  const handleLevelSelect = (level: WellBeingLevel) => {
    setSelectedLevel(level);
    setStep('student-info');
  };

  const handleStudentInfoSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (studentInfo.name && studentInfo.standard) {
      setStep('questions');
    }
  };

  const handleAnswer = (indicator: ResponseIndicator) => {
    const questionId = filteredQuestions[currentQuestionIndex].id;
    const newAnswers = { ...answers, [questionId]: indicator };
    setAnswers(newAnswers);

    if (currentQuestionIndex < filteredQuestions.length - 1) {
      setCurrentQuestionIndex(prev => prev + 1);
    } else {
      // Calculate scores
      const values = Object.values(newAnswers);
      const score = {
        healthy: values.filter(v => v === ResponseIndicator.HEALTHY).length,
        concern: values.filter(v => v === ResponseIndicator.CONCERN).length,
        redFlag: values.filter(v => v === ResponseIndicator.RED_FLAG).length,
      };

      const submission: Submission = {
        id: Math.random().toString(36).substr(2, 9),
        student: studentInfo,
        level: selectedLevel!,
        answers: newAnswers,
        score,
        timestamp: Date.now(),
      };

      onComplete(submission);
      setStep('completed');
    }
  };

  if (step === 'level-select') {
    return (
      <div className="max-w-4xl mx-auto px-4 py-12">
        <div className="text-center mb-12">
          <h2 className="text-3xl font-bold text-slate-900 mb-4">Student Well-Being Check</h2>
          <p className="text-slate-600">Please select your grade group to begin the assessment.</p>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          {Object.values(WellBeingLevel).map((level) => (
            <button
              key={level}
              onClick={() => handleLevelSelect(level)}
              className="bento-card text-left hover:border-emerald-500 border-2 border-transparent group"
            >
              <div className="flex items-center justify-between">
                <div>
                  <h3 className="text-xl font-bold text-slate-900 group-hover:text-emerald-600 transition-colors">{level}</h3>
                  <p className="text-sm text-slate-500 mt-1">Specialized wellness screening</p>
                </div>
                <div className="w-12 h-12 rounded-full bg-emerald-50 flex items-center justify-center text-emerald-600 font-bold">
                  →
                </div>
              </div>
            </button>
          ))}
        </div>
      </div>
    );
  }

  if (step === 'student-info') {
    return (
      <div className="max-w-2xl mx-auto px-4 py-12">
        <div className="bento-card">
          <h2 className="text-2xl font-bold text-slate-900 mb-6">Student Information</h2>
          <form onSubmit={handleStudentInfoSubmit} className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Full Name</label>
              <input
                required
                type="text"
                value={studentInfo.name}
                onChange={e => setStudentInfo(prev => ({ ...prev, name: e.target.value }))}
                className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-emerald-500 focus:border-transparent outline-none transition-all"
                placeholder="Enter student name"
              />
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Standard / Class</label>
                <input
                  required
                  type="text"
                  value={studentInfo.standard}
                  onChange={e => setStudentInfo(prev => ({ ...prev, standard: e.target.value }))}
                  className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-emerald-500 focus:border-transparent outline-none transition-all"
                  placeholder="e.g. 5th"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Age</label>
                <input
                  required
                  type="number"
                  value={studentInfo.age}
                  onChange={e => setStudentInfo(prev => ({ ...prev, age: e.target.value }))}
                  className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-emerald-500 focus:border-transparent outline-none transition-all"
                  placeholder="Years"
                />
              </div>
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">School Name</label>
              <input
                required
                type="text"
                value={studentInfo.school}
                onChange={e => setStudentInfo(prev => ({ ...prev, school: e.target.value }))}
                className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-emerald-500 focus:border-transparent outline-none transition-all"
                placeholder="Name of school"
              />
            </div>
            <button
              type="submit"
              className="w-full mt-6 bg-emerald-600 text-white font-bold py-3 rounded-xl hover:bg-emerald-700 transition-colors shadow-lg shadow-emerald-200"
            >
              Start Assessment
            </button>
          </form>
        </div>
      </div>
    );
  }

  if (step === 'questions') {
    const q = filteredQuestions[currentQuestionIndex];
    return (
      <div className="max-w-4xl mx-auto px-4 py-12">
        <div className="mb-8">
          <div className="flex justify-between items-center mb-2">
            <span className="text-xs font-bold text-emerald-600 uppercase tracking-widest">{selectedLevel}</span>
            <span className="text-sm font-medium text-slate-500">Question {currentQuestionIndex + 1} of {filteredQuestions.length}</span>
          </div>
          <div className="w-full bg-slate-100 rounded-full h-2">
            <div 
              className="bg-emerald-500 h-2 rounded-full transition-all duration-500" 
              style={{ width: `${progress}%` }}
            ></div>
          </div>
        </div>

        <div className="mb-10 animate-in fade-in duration-700">
          <h2 className="text-2xl md:text-3xl font-bold text-slate-900 mb-2 leading-tight">
            {q.textEn}
          </h2>
          <h2 className="text-xl md:text-2xl font-medium text-slate-500 italic">
            {q.textHi}
          </h2>
        </div>

        <div className="grid grid-cols-1 gap-4">
          {q.options.map((opt) => (
            <button
              key={opt.id}
              onClick={() => handleAnswer(opt.indicator)}
              className="bento-card text-left hover:bg-emerald-50 border-2 border-transparent hover:border-emerald-200 transition-all group flex flex-col md:flex-row md:items-center justify-between p-6"
            >
              <div className="flex-grow">
                <p className="text-lg font-semibold text-slate-800 group-hover:text-emerald-900">{opt.en}</p>
                <p className="text-md text-slate-500 mt-1 font-medium">{opt.hi}</p>
              </div>
              <div className="mt-4 md:mt-0 md:ml-6 flex-shrink-0">
                 <div className="w-8 h-8 rounded-full border-2 border-slate-200 group-hover:border-emerald-500 flex items-center justify-center">
                    <div className="w-4 h-4 rounded-full bg-emerald-500 opacity-0 group-hover:opacity-100 transition-opacity"></div>
                 </div>
              </div>
            </button>
          ))}
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-xl mx-auto px-4 py-24 text-center">
      <div className="w-20 h-20 bg-emerald-100 text-emerald-600 rounded-full flex items-center justify-center text-4xl mx-auto mb-8 animate-bounce">
        ✓
      </div>
      <h2 className="text-3xl font-bold text-slate-900 mb-4">Great Job!</h2>
      <p className="text-slate-600 text-lg mb-8">
        Your response has been successfully recorded. Your teacher or school counselor will review the summary to help provide the best support for your well-being.
      </p>
      <button
        onClick={() => window.location.reload()}
        className="px-8 py-3 bg-slate-900 text-white rounded-xl font-bold hover:bg-slate-800 transition-all"
      >
        Return to Home
      </button>
    </div>
  );
};

export default Quiz;

import React, { useState } from 'react';
import { Submission, ResponseIndicator } from '../types';

interface AdminDashboardProps {
  submissions: Submission[];
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ submissions }) => {
  const [filter, setFilter] = useState<'all' | 'red-flag'>('all');

  const filteredData = submissions.filter(s => 
    filter === 'all' ? true : s.score.redFlag > 0
  );

  const stats = {
    total: submissions.length,
    redFlags: submissions.filter(s => s.score.redFlag > 0).length,
    healthy: submissions.filter(s => s.score.redFlag === 0 && s.score.concern === 0).length,
  };

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-12">
      <div className="mb-10">
        <h2 className="text-3xl font-bold text-slate-900">Educator Dashboard</h2>
        <p className="text-slate-500 mt-1">Student well-being monitoring & screening summary</p>
      </div>

      {/* Stats Cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-10">
        <div className="bento-card bg-white border-l-4 border-emerald-500">
          <p className="text-slate-500 text-sm font-medium uppercase tracking-wider">Total Submissions</p>
          <p className="text-4xl font-bold text-slate-900 mt-2">{stats.total}</p>
        </div>
        <div className="bento-card bg-white border-l-4 border-amber-500">
          <p className="text-slate-500 text-sm font-medium uppercase tracking-wider">Healthy / Stable</p>
          <p className="text-4xl font-bold text-slate-900 mt-2">{stats.healthy}</p>
        </div>
        <div className="bento-card bg-red-50 border-l-4 border-red-500">
          <p className="text-red-600 text-sm font-bold uppercase tracking-wider">Urgent Red Flags</p>
          <p className="text-4xl font-bold text-red-700 mt-2">{stats.redFlags}</p>
        </div>
      </div>

      {/* Control Bar */}
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center mb-6 gap-4">
        <div className="flex space-x-2">
          <button 
            onClick={() => setFilter('all')}
            className={`px-4 py-2 rounded-lg text-sm font-semibold transition-all ${filter === 'all' ? 'bg-slate-900 text-white' : 'bg-white text-slate-600 hover:bg-slate-100'}`}
          >
            All Submissions
          </button>
          <button 
            onClick={() => setFilter('red-flag')}
            className={`px-4 py-2 rounded-lg text-sm font-semibold transition-all ${filter === 'red-flag' ? 'bg-red-600 text-white' : 'bg-white text-red-600 hover:bg-red-50'}`}
          >
            Show Red Flags Only
          </button>
        </div>
      </div>

      {/* Table */}
      <div className="bg-white rounded-3xl overflow-hidden shadow-sm border border-slate-100">
        <div className="overflow-x-auto">
          <table className="min-w-full divide-y divide-slate-100">
            <thead className="bg-slate-50">
              <tr>
                <th className="px-6 py-4 text-left text-xs font-bold text-slate-500 uppercase tracking-wider">Student Name</th>
                <th className="px-6 py-4 text-left text-xs font-bold text-slate-500 uppercase tracking-wider">Std / Class</th>
                <th className="px-6 py-4 text-left text-xs font-bold text-slate-500 uppercase tracking-wider">Level</th>
                <th className="px-6 py-4 text-left text-xs font-bold text-slate-500 uppercase tracking-wider">Assessment Status</th>
                <th className="px-6 py-4 text-left text-xs font-bold text-slate-500 uppercase tracking-wider">Date</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredData.length === 0 ? (
                <tr>
                  <td colSpan={5} className="px-6 py-12 text-center text-slate-400">No submissions found.</td>
                </tr>
              ) : (
                filteredData.map((s) => (
                  <tr key={s.id} className="hover:bg-slate-50 transition-colors">
                    <td className="px-6 py-4 whitespace-nowrap">
                      <div className="text-sm font-bold text-slate-900">{s.student.name}</div>
                      <div className="text-xs text-slate-500">{s.student.school}</div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-700">
                      {s.student.standard}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <span className="px-2 py-1 text-xs font-semibold rounded-full bg-slate-100 text-slate-600">
                        {s.level}
                      </span>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <div className="flex space-x-2">
                        {s.score.redFlag > 0 && (
                          <span className="px-3 py-1 text-xs font-bold rounded-full bg-red-100 text-red-700 animate-pulse">
                            {s.score.redFlag} CRITICAL FLAG(S)
                          </span>
                        )}
                        {s.score.concern > 0 && (
                          <span className="px-3 py-1 text-xs font-bold rounded-full bg-amber-100 text-amber-700">
                            {s.score.concern} CONCERN(S)
                          </span>
                        )}
                        {s.score.redFlag === 0 && s.score.concern === 0 && (
                          <span className="px-3 py-1 text-xs font-bold rounded-full bg-emerald-100 text-emerald-700">
                            STABLE / HEALTHY
                          </span>
                        )}
                      </div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-xs text-slate-500">
                      {new Date(s.timestamp).toLocaleDateString()}
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

