export enum WellBeingLevel {
  LEVEL_1 = 'Std 1 to 3',
  LEVEL_2 = 'Std 4 to 6',
  LEVEL_3 = 'Std 7 to 8',
  LEVEL_4 = 'Std 9 to 10',
}

export enum ResponseIndicator {
  HEALTHY = 'Positive/Healthy Adjustment',
  CONCERN = 'Developing Concern/Mild Anxiety',
  RED_FLAG = 'CRITICAL RED FLAG',
}

export enum UserRole {
  ADMIN = 'ADMIN',
  TEACHER = 'TEACHER',
  STUDENT = 'STUDENT'
}

export interface User {
  username: string;
  role: UserRole;
}

export interface Option {
  id: string;
  en: string;
  hi: string;
  indicator: ResponseIndicator;
}

export interface Question {
  id: string;
  level: WellBeingLevel;
  textEn: string;
  textHi: string;
  options: Option[];
}

export interface StudentInfo {
  name: string;
  age: string;
  standard: string;
  school: string;
}

export interface Submission {
  id: string;
  student: StudentInfo;
  level: WellBeingLevel;
  answers: { [questionId: string]: ResponseIndicator };
  score: {
    healthy: number;
    concern: number;
    redFlag: number;
    total: number;
  };
  conclusion: string;
  riskLevel: 'Healthy' | 'Concern' | 'Critical';
  timestamp: number;
}

import { Question, Submission, ResponseIndicator } from '../types';
import { QUIZ_DATA } from '../constants';

const QUESTIONS_KEY = 'nitgyanam_questions';
const SUBMISSIONS_KEY = 'nitgyanam_submissions';

export const api = {
  fetchQuestions: (): Question[] => {
    const saved = localStorage.getItem(QUESTIONS_KEY);
    if (!saved) {
      localStorage.setItem(QUESTIONS_KEY, JSON.stringify(QUIZ_DATA));
      return QUIZ_DATA;
    }
    return JSON.parse(saved);
  },

  updateQuestions: (questions: Question[]) => {
    localStorage.setItem(QUESTIONS_KEY, JSON.stringify(questions));
  },

  submitAssessment: (submission: Submission) => {
    const saved = localStorage.getItem(SUBMISSIONS_KEY);
    const submissions: Submission[] = saved ? JSON.parse(saved) : [];
    submissions.unshift(submission);
    localStorage.setItem(SUBMISSIONS_KEY, JSON.stringify(submissions));
    return submission;
  },

  fetchSubmissions: (): Submission[] => {
    const saved = localStorage.getItem(SUBMISSIONS_KEY);
    return saved ? JSON.parse(saved) : [];
  },

  calculateConclusion: (answers: ResponseIndicator[]) => {
    const total = answers.length;
    const counts = {
      healthy: answers.filter(a => a === ResponseIndicator.HEALTHY).length,
      concern: answers.filter(a => a === ResponseIndicator.CONCERN).length,
      redFlag: answers.filter(a => a === ResponseIndicator.RED_FLAG).length,
    };

    const healthyPct = (counts.healthy / total) * 100;
    const concernPct = (counts.concern / total) * 100;
    const redFlagPct = (counts.redFlag / total) * 100;

    if (counts.redFlag > 0 || redFlagPct > 20) {
      return {
        riskLevel: 'Critical' as const,
        conclusion: 'URGENT RED FLAG: Potential deep distress detected. Immediate physical intervention and parental notification required.'
      };
    } else if (concernPct > 30) {
      return {
        riskLevel: 'Concern' as const,
        conclusion: 'Student is experiencing moderate stress/anxiety. Recommend counseling.'
      };
    } else {
      return {
        riskLevel: 'Healthy' as const,
        conclusion: 'Student shows high resilience and stable emotional health.'
      };
    }
  }
};

