import React, { useState, useEffect } from 'react';
import { Question, WellBeingLevel, ResponseIndicator } from '../types';
import { api } from '../services/api';

const QuestionManager: React.FC = () => {
  const [questions, setQuestions] = useState<Question[]>([]);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [formData, setFormData] = useState<Partial<Question>>({});

  useEffect(() => {
    setQuestions(api.fetchQuestions());
  }, []);

  const handleSave = () => {
    let updated;
    if (editingId === 'new') {
      const newQ: Question = {
        ...formData as Question,
        id: `custom_${Date.now()}`,
      };
      updated = [...questions, newQ];
    } else {
      updated = questions.map(q => q.id === editingId ? { ...q, ...formData } : q);
    }
    setQuestions(updated);
    api.updateQuestions(updated);
    setEditingId(null);
  };

  const deleteQuestion = (id: string) => {
    const updated = questions.filter(q => q.id !== id);
    setQuestions(updated);
    api.updateQuestions(updated);
  };

  const startEdit = (q: Question) => {
    setEditingId(q.id);
    setFormData(q);
  };

  const startNew = () => {
    setEditingId('new');
    setFormData({
      level: WellBeingLevel.LEVEL_1,
      textEn: '',
      textHi: '',
      options: [
        { id: 'a', en: '', hi: '', indicator: ResponseIndicator.HEALTHY },
        { id: 'b', en: '', hi: '', indicator: ResponseIndicator.HEALTHY },
        { id: 'c', en: '', hi: '', indicator: ResponseIndicator.CONCERN },
        { id: 'd', en: '', hi: '', indicator: ResponseIndicator.RED_FLAG },
      ]
    });
  };

  return (
    <div className="max-w-6xl mx-auto p-6">
      <div className="flex justify-between items-center mb-8">
        <h2 className="text-3xl font-bold text-[#1A1A1A]">MCQ Manager</h2>
        <button 
          onClick={startNew}
          className="bg-[#FFD700] text-[#1A1A1A] px-6 py-2 rounded-xl font-bold hover:bg-[#e6c200] transition-all"
        >
          + Add Question
        </button>
      </div>

      {editingId && (
        <div className="fixed inset-0 bg-black/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-3xl p-8 max-w-2xl w-full max-h-[90vh] overflow-y-auto">
            <h3 className="text-2xl font-bold mb-6">{editingId === 'new' ? 'New Question' : 'Edit Question'}</h3>
            <div className="space-y-4">
              <div>
                <label className="block text-sm font-bold text-gray-700">Level</label>
                <select 
                  value={formData.level}
                  onChange={e => setFormData({...formData, level: e.target.value as WellBeingLevel})}
                  className="w-full p-2 border rounded-lg"
                >
                  {Object.values(WellBeingLevel).map(l => <option key={l} value={l}>{l}</option>)}
                </select>
              </div>
              <div>
                <label className="block text-sm font-bold text-gray-700">Question (English)</label>
                <input 
                  value={formData.textEn}
                  onChange={e => setFormData({...formData, textEn: e.target.value})}
                  className="w-full p-2 border rounded-lg"
                />
              </div>
              <div>
                <label className="block text-sm font-bold text-gray-700">Question (Hindi)</label>
                <input 
                  value={formData.textHi}
                  onChange={e => setFormData({...formData, textHi: e.target.value})}
                  className="w-full p-2 border rounded-lg"
                />
              </div>

              <div className="space-y-3">
                <p className="font-bold text-sm">Options & Logic</p>
                {formData.options?.map((opt, idx) => (
                  <div key={idx} className="p-4 border rounded-xl bg-gray-50 space-y-2">
                    <div className="flex justify-between items-center">
                      <span className="font-bold text-xs uppercase text-gray-400">Option {opt.id.toUpperCase()}</span>
                      <select 
                        value={opt.indicator}
                        onChange={e => {
                          const newOpts = [...(formData.options || [])];
                          newOpts[idx].indicator = e.target.value as ResponseIndicator;
                          setFormData({...formData, options: newOpts});
                        }}
                        className="text-xs border rounded p-1"
                      >
                        {Object.values(ResponseIndicator).map(i => <option key={i} value={i}>{i}</option>)}
                      </select>
                    </div>
                    <input 
                      placeholder="English"
                      value={opt.en}
                      onChange={e => {
                        const newOpts = [...(formData.options || [])];
                        newOpts[idx].en = e.target.value;
                        setFormData({...formData, options: newOpts});
                      }}
                      className="w-full p-2 text-sm border rounded"
                    />
                    <input 
                      placeholder="Hindi"
                      value={opt.hi}
                      onChange={e => {
                        const newOpts = [...(formData.options || [])];
                        newOpts[idx].hi = e.target.value;
                        setFormData({...formData, options: newOpts});
                      }}
                      className="w-full p-2 text-sm border rounded"
                    />
                  </div>
                ))}
