            </div>
            <div className="flex justify-end space-x-4 mt-8">
              <button onClick={() => setEditingId(null)} className="px-6 py-2 text-gray-500 font-bold">Cancel</button>
              <button onClick={handleSave} className="px-8 py-2 bg-[#1A1A1A] text-white rounded-xl font-bold">Save Changes</button>
