import React, { useState, useMemo, useEffect } from 'react';
import { WellBeingLevel, Question, ResponseIndicator, StudentInfo, Submission } from '../types';
import { api } from '../services/api';

interface QuizProps {
  onComplete: (submission: Submission) => void;
}

type QuizStep = 'level-select' | 'student-info' | 'questions' | 'completed';

const Quiz: React.FC<QuizProps> = ({ onComplete }) => {
  const [step, setStep] = useState<QuizStep>('level-select');
  const [questions, setQuestions] = useState<Question[]>([]);
  const [selectedLevel, setSelectedLevel] = useState<WellBeingLevel | null>(null);
  const [studentInfo, setStudentInfo] = useState<StudentInfo>({ name: '', age: '', standard: '', school: '' });
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [answers, setAnswers] = useState<{ [id: string]: ResponseIndicator }>({});

  useEffect(() => {
    setQuestions(api.fetchQuestions());
  }, []);

  const filteredQuestions = useMemo(() => {
    return questions.filter(q => q.level === selectedLevel);
  }, [selectedLevel, questions]);

  const progress = filteredQuestions.length > 0 
    ? Math.round(((currentQuestionIndex) / filteredQuestions.length) * 100) 
    : 0;

  const handleAnswer = (indicator: ResponseIndicator) => {
    const questionId = filteredQuestions[currentQuestionIndex].id;
    const newAnswers = { ...answers, [questionId]: indicator };
    setAnswers(newAnswers);

    if (currentQuestionIndex < filteredQuestions.length - 1) {
      setCurrentQuestionIndex(prev => prev + 1);
    } else {
      const answerList = Object.values(newAnswers);
      const { riskLevel, conclusion } = api.calculateConclusion(answerList);

      const submission: Submission = {
        id: Math.random().toString(36).substr(2, 9),
        student: studentInfo,
        level: selectedLevel!,
        answers: newAnswers,
        score: {
          healthy: answerList.filter(v => v === ResponseIndicator.HEALTHY).length,
          concern: answerList.filter(v => v === ResponseIndicator.CONCERN).length,
          redFlag: answerList.filter(v => v === ResponseIndicator.RED_FLAG).length,
          total: answerList.length
        },
        riskLevel,
        conclusion,
        timestamp: Date.now(),
      };

      api.submitAssessment(submission);
      onComplete(submission);
      setStep('completed');
    }
  };

  // Rendering logic remains similar but uses the new api-provided questions
  if (step === 'level-select') {
    return (
      <div className="max-w-4xl mx-auto px-4 py-12">
        <div className="text-center mb-12">
          <h2 className="text-3xl font-bold text-slate-900 mb-4">Well-Being Screening</h2>
          <p className="text-slate-600">Select your academic group to start the confidential assessment.</p>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          {Object.values(WellBeingLevel).map((level) => (
            <button
              key={level}
              onClick={() => { setSelectedLevel(level); setStep('student-info'); }}
              className="bento-card text-left hover:border-[#FFD700] border-2 border-transparent group"
            >
              <div className="flex items-center justify-between">
                <div>
                  <h3 className="text-xl font-bold text-slate-900 group-hover:text-[#1A1A1A] transition-colors">{level}</h3>
                  <p className="text-xs text-slate-500 font-bold uppercase tracking-widest mt-1">Screening Active</p>
                </div>
                <div className="w-12 h-12 rounded-full bg-yellow-50 flex items-center justify-center text-[#FFD700] font-bold">→</div>
              </div>
            </button>
          ))}
        </div>
      </div>
    );
  }

  if (step === 'student-info') {
    return (
      <div className="max-w-2xl mx-auto px-4 py-12">
        <div className="bento-card">
          <h2 className="text-2xl font-bold text-slate-900 mb-6">Student Information</h2>
          <form onSubmit={e => { e.preventDefault(); setStep('questions'); }} className="space-y-4">
            <input required placeholder="Full Name" className="w-full px-4 py-3 rounded-xl border" onChange={e => setStudentInfo({...studentInfo, name: e.target.value})} />
            <div className="grid grid-cols-2 gap-4">
               <input required placeholder="Standard" className="w-full px-4 py-3 rounded-xl border" onChange={e => setStudentInfo({...studentInfo, standard: e.target.value})} />
               <input required type="number" placeholder="Age" className="w-full px-4 py-3 rounded-xl border" onChange={e => setStudentInfo({...studentInfo, age: e.target.value})} />
            </div>
            <input required placeholder="School Name" className="w-full px-4 py-3 rounded-xl border" onChange={e => setStudentInfo({...studentInfo, school: e.target.value})} />
            <button type="submit" className="w-full mt-6 bg-[#1A1A1A] text-white font-bold py-4 rounded-2xl">Begin Assessment</button>
          </form>
        </div>
      </div>
    );
  }

  if (step === 'questions') {
    const q = filteredQuestions[currentQuestionIndex];
    if (!q) return <div>No questions available for this level.</div>;
    return (
      <div className="max-w-4xl mx-auto px-4 py-12">
        <div className="mb-8 flex items-center justify-between">
          <span className="text-xs font-bold text-gray-400 uppercase tracking-widest">{selectedLevel} | Q {currentQuestionIndex + 1}</span>
          <div className="w-48 bg-gray-100 rounded-full h-1.5"><div className="bg-[#FFD700] h-1.5 rounded-full" style={{ width: `${progress}%` }}></div></div>
        </div>
        <h2 className="text-3xl font-bold mb-2">{q.textEn}</h2>
        <h3 className="text-xl text-slate-500 italic mb-10">{q.textHi}</h3>
        <div className="grid gap-4">
          {q.options.map(opt => (
            <button key={opt.id} onClick={() => handleAnswer(opt.indicator)} className="bento-card text-left hover:bg-yellow-50 border-2 border-transparent hover:border-[#FFD700] p-6 group">
              <p className="font-bold text-lg text-slate-800">{opt.en}</p>
              <p className="text-slate-500 italic">{opt.hi}</p>
            </button>
          ))}
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-xl mx-auto px-4 py-24 text-center">
      <div className="w-20 h-20 bg-yellow-100 text-[#FFD700] rounded-full flex items-center justify-center text-4xl mx-auto mb-8">✓</div>
      <h2 className="text-3xl font-bold mb-4">Assessment Submitted</h2>
      <p className="text-slate-600 mb-8">Your clinical response has been logged securely for professional review.</p>
      <button onClick={() => window.location.reload()} className="px-8 py-3 bg-[#1A1A1A] text-white rounded-xl font-bold">Close Portal</button>
    </div>
  );
};

