import React, { useState, useMemo, useEffect } from 'react';
import { WellBeingLevel, Question, ResponseIndicator, StudentInfo, Submission } from '../types';
import { api } from '../services/api';

interface QuizProps {
  onComplete: (submission: Submission) => void;
}

type QuizStep = 'level-select' | 'student-info' | 'questions' | 'completed';

const Quiz: React.FC<QuizProps> = ({ onComplete }) => {
  const [step, setStep] = useState<QuizStep>('level-select');
  const [questions, setQuestions] = useState<Question[]>([]);
  const [selectedLevel, setSelectedLevel] = useState<WellBeingLevel | null>(null);
  const [studentInfo, setStudentInfo] = useState<StudentInfo>({ name: '', age: '', standard: '', school: '' });
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [answers, setAnswers] = useState<{ [id: string]: ResponseIndicator }>({});

  useEffect(() => {
    setQuestions(api.fetchQuestions());
  }, []);

  const filteredQuestions = useMemo(() => {
    return questions.filter(q => q.level === selectedLevel);
  }, [selectedLevel, questions]);

  const progress = filteredQuestions.length > 0 
    ? Math.round(((currentQuestionIndex) / filteredQuestions.length) * 100) 
    : 0;

  const handleAnswer = (indicator: ResponseIndicator) => {
    const questionId = filteredQuestions[currentQuestionIndex].id;
    const newAnswers = { ...answers, [questionId]: indicator };
    setAnswers(newAnswers);

    if (currentQuestionIndex < filteredQuestions.length - 1) {
      setCurrentQuestionIndex(prev => prev + 1);
    } else {
      const answerList = Object.values(newAnswers);
      const { riskStatus, conclusion } = api.analyzeResults(answerList);

      const submission: Submission = {
        id: `sub_${Math.random().toString(36).substr(2, 9)}`,
        student: studentInfo,
        level: selectedLevel!,
        answers: newAnswers,
        metrics: {
          healthyCount: answerList.filter(v => v === ResponseIndicator.HEALTHY).length,
          concernCount: answerList.filter(v => v === ResponseIndicator.CONCERN).length,
          redFlagCount: answerList.filter(v => v === ResponseIndicator.RED_FLAG).length,
          totalQuestions: answerList.length
        },
        riskStatus,
        conclusion,
        timestamp: Date.now(),
      };

      api.submitAssessment(submission);
      onComplete(submission);
      setStep('completed');
    }
  };

  if (step === 'level-select') {
    return (
      <div className="max-w-4xl mx-auto px-6 py-20 animate-fade-in">
        <div className="text-center mb-16">
          <h2 className="text-4xl md:text-5xl font-black text-charcoal tracking-tighter uppercase mb-4">Select Academic Group</h2>
          <p className="text-slate-500 font-medium">Screening logic tailored to developmental stages</p>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          {Object.values(WellBeingLevel).map((level) => (
            <button
              key={level}
              onClick={() => { setSelectedLevel(level); setStep('student-info'); }}
              className="bg-white p-10 rounded-[2.5rem] text-left border-4 border-slate-50 hover:border-gold transition-all duration-300 group shadow-xl shadow-slate-100/50"
            >
              <div className="flex items-center justify-between">
                <div>
                  <h3 className="text-2xl font-black text-charcoal group-hover:text-gold transition-colors">{level}</h3>
                  <p className="text-[10px] font-black text-slate-300 uppercase tracking-[0.2em] mt-2 group-hover:text-charcoal transition-colors">Start Assessment</p>
                </div>
                <div className="w-14 h-14 rounded-2xl bg-slate-50 flex items-center justify-center text-slate-300 group-hover:bg-gold group-hover:text-white transition-all">
                  <span className="text-2xl font-bold">→</span>
                </div>
              </div>
            </button>
          ))}
        </div>
      </div>
    );
  }

  if (step === 'student-info') {
    return (
      <div className="max-w-2xl mx-auto px-6 py-20 animate-fade-in">
        <div className="bg-white rounded-[3rem] p-10 border-4 border-slate-50 shadow-2xl">
          <h2 className="text-3xl font-black text-charcoal tracking-tighter uppercase mb-8">Identity Verification</h2>
          <form onSubmit={e => { e.preventDefault(); setStep('questions'); }} className="space-y-6">
            <div className="space-y-2">
               <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest">Student Full Name</label>
               <input required className="w-full px-6 py-4 rounded-2xl bg-slate-50 border-2 border-slate-100 focus:border-gold outline-none font-bold transition-all" onChange={e => setStudentInfo({...studentInfo, name: e.target.value})} />
            </div>
            <div className="grid grid-cols-2 gap-4">
               <div className="space-y-2">
                  <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest">Standard</label>
                  <input required className="w-full px-6 py-4 rounded-2xl bg-slate-50 border-2 border-slate-100 focus:border-gold outline-none font-bold transition-all" onChange={e => setStudentInfo({...studentInfo, standard: e.target.value})} />
               </div>
               <div className="space-y-2">
                  <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest">Age</label>
                  <input required type="number" className="w-full px-6 py-4 rounded-2xl bg-slate-50 border-2 border-slate-100 focus:border-gold outline-none font-bold transition-all" onChange={e => setStudentInfo({...studentInfo, age: e.target.value})} />
               </div>
            </div>
            <div className="space-y-2">
               <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest">School Name</label>
               <input required className="w-full px-6 py-4 rounded-2xl bg-slate-50 border-2 border-slate-100 focus:border-gold outline-none font-bold transition-all" onChange={e => setStudentInfo({...studentInfo, school: e.target.value})} />
            </div>
            <button type="submit" className="w-full mt-6 bg-charcoal text-white font-black py-5 rounded-[2rem] shadow-2xl hover:bg-black transition-all uppercase tracking-widest text-xs">Verify & Begin</button>
          </form>
        </div>
      </div>
    );
  }

  if (step === 'questions') {
    const q = filteredQuestions[currentQuestionIndex];
    if (!q) return <div className="p-20 text-center font-black">PREPARING SCREENING MODULE...</div>;

    return (
      <div className="max-w-5xl mx-auto px-6 py-16 animate-fade-in">
        <div className="mb-12 flex items-center justify-between">
          <div>
            <span className="text-[10px] font-black text-gold uppercase tracking-widest bg-charcoal px-3 py-1 rounded-full mr-3">{selectedLevel}</span>
            <span className="text-xs font-bold text-slate-300 uppercase tracking-[0.2em]">Clinical Probe {currentQuestionIndex + 1} / {filteredQuestions.length}</span>
          </div>
          <div className="w-48 bg-slate-100 rounded-full h-2 overflow-hidden">
            <div className="bg-gold h-full transition-all duration-700 shadow-[0_0_10px_rgba(255,215,0,0.5)]" style={{ width: `${progress}%` }}></div>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-10 mb-16">
          <div className="p-10 bg-white rounded-[3rem] border-2 border-slate-50 shadow-xl">
             <p className="text-[10px] font-black text-slate-300 uppercase tracking-widest mb-4">English Formulation</p>
             <h2 className="text-2xl md:text-3xl font-black text-charcoal leading-tight">{q.textEn}</h2>
          </div>
          <div className="p-10 bg-gold/5 rounded-[3rem] border-2 border-gold/10 shadow-xl">
             <p className="text-[10px] font-black text-gold uppercase tracking-widest mb-4">Hindi Formulation (नीतिज्ञानम्)</p>
             <h2 className="text-2xl md:text-3xl font-hindi font-black text-charcoal leading-tight">{q.textHi}</h2>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          {q.options.map(opt => (
            <button 
              key={opt.id} 
              onClick={() => handleAnswer(opt.indicator)} 
              className="bg-white p-8 rounded-[2rem] text-left border-2 border-slate-50 hover:border-gold hover:shadow-gold transition-all duration-300 group"
            >
              <div className="flex items-start space-x-6">
                <div className="w-10 h-10 rounded-xl bg-slate-50 flex items-center justify-center font-black text-slate-400 group-hover:bg-gold group-hover:text-charcoal transition-all">
                  {opt.id.toUpperCase()}
                </div>
                <div className="flex-grow">
                  <p className="font-bold text-lg text-charcoal mb-1 leading-snug">{opt.en}</p>
                  <p className="text-slate-500 font-hindi font-medium italic">{opt.hi}</p>
                </div>
              </div>
            </button>
          ))}
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-xl mx-auto px-6 py-32 text-center animate-fade-in">
      <div className="w-24 h-24 bg-gold text-charcoal rounded-full flex items-center justify-center text-5xl mx-auto mb-10 shadow-gold transform hover:rotate-12 transition-transform">✓</div>
      <h2 className="text-4xl font-black text-charcoal uppercase tracking-tighter mb-4">Session Securely Logged</h2>
      <p className="text-slate-500 font-medium mb-12">Your psychological indicators have been processed by our clinical engine. The school counselor will be notified of any moderate or critical flags.</p>
      <button 
        onClick={() => window.location.reload()} 
        className="px-12 py-5 bg-charcoal text-white rounded-[2rem] font-black uppercase tracking-widest text-xs shadow-2xl hover:scale-105 transition-transform"
      >
        Exit Portal
      </button>
    </div>
  );
};

export default Quiz;

