import React, { useState, useMemo, useEffect } from 'react';
import { WellBeingLevel, Question, ResponseIndicator, StudentInfo, Submission } from '../types';
import { api } from '../services/api';

interface QuizProps {
  onComplete: (submission: Submission) => void;
}

type QuizStep = 'level-select' | 'student-info' | 'questions' | 'completed';

const Quiz: React.FC<QuizProps> = ({ onComplete }) => {
  const [step, setStep] = useState<QuizStep>('level-select');
  const [questions, setQuestions] = useState<Question[]>([]);
  const [selectedLevel, setSelectedLevel] = useState<WellBeingLevel | null>(null);
  const [studentInfo, setStudentInfo] = useState<StudentInfo>({ name: '', age: '', standard: '', school: '' });
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [answers, setAnswers] = useState<{ [id: string]: ResponseIndicator }>({});

  useEffect(() => {
    setQuestions(api.fetchQuestions());
  }, []);

  const filteredQuestions = useMemo(() => {
    return questions.filter(q => q.level === selectedLevel);
  }, [selectedLevel, questions]);

  const progress = filteredQuestions.length > 0 
    ? Math.round(((currentQuestionIndex) / filteredQuestions.length) * 100) 
    : 0;

  const handleAnswer = (indicator: ResponseIndicator) => {
    const questionId = filteredQuestions[currentQuestionIndex].id;
    const newAnswers = { ...answers, [questionId]: indicator };
    setAnswers(newAnswers);

    if (currentQuestionIndex < filteredQuestions.length - 1) {
      setCurrentQuestionIndex(prev => prev + 1);
    } else {
      const answerList = Object.values(newAnswers);
      const { riskStatus, conclusion } = api.analyzeResults(answerList);

      const submission: Submission = {
        id: `sub_${Math.random().toString(36).substr(2, 9)}`,
        student: studentInfo,
        level: selectedLevel!,
        answers: newAnswers,
        metrics: {
          healthyCount: answerList.filter(v => v === ResponseIndicator.HEALTHY).length,
          concernCount: answerList.filter(v => v === ResponseIndicator.CONCERN).length,
          redFlagCount: answerList.filter(v => v === ResponseIndicator.RED_FLAG).length,
          totalQuestions: answerList.length
        },
        riskStatus,
        conclusion,
        timestamp: Date.now(),
      };

      api.submitAssessment(submission);
      onComplete(submission);
      setStep('completed');
    }
  };

  if (step === 'level-select') {
    return (
      <div className="max-w-5xl mx-auto px-6 py-24 animate-fade-in">
        <div className="text-center mb-16">
          <h2 className="text-5xl font-black text-white tracking-tighter uppercase mb-6">Select Assessment Tier</h2>
          <p className="text-gray-500 font-bold uppercase tracking-widest text-xs">Developmentally tailored diagnostic modules</p>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
          {Object.values(WellBeingLevel).map((level) => (
            <button
              key={level}
              onClick={() => { setSelectedLevel(level); setStep('student-info'); }}
              className="bento-card p-12 text-left group border-white/5 hover:border-gold/50"
            >
              <div className="flex items-center justify-between">
                <div>
                  <h3 className="text-3xl font-black text-white group-hover:text-gold transition-colors tracking-tighter">{level}</h3>
                  <p className="text-[10px] font-black text-gray-500 uppercase tracking-[0.2em] mt-3">Psychological Baseline Module</p>
                </div>
                <div className="w-16 h-16 rounded-3xl bg-white/5 flex items-center justify-center text-white/20 group-hover:bg-gold group-hover:text-black transition-all">
                  <span className="text-3xl font-bold">→</span>
                </div>
              </div>
            </button>
          ))}
        </div>
      </div>
    );
  }

  if (step === 'student-info') {
    return (
      <div className="max-w-2xl mx-auto px-6 py-24 animate-fade-in">
        <div className="bento-card p-12 border-gold/20 shadow-2xl">
          <h2 className="text-3xl font-black text-white tracking-tighter uppercase mb-10">Identity Verification</h2>
          <form onSubmit={e => { e.preventDefault(); setStep('questions'); }} className="space-y-8">
            <div className="space-y-3">
               <label className="text-[10px] font-black uppercase text-gray-500 tracking-widest">Full Legal Name</label>
               <input required placeholder="Enter student name" className="w-full px-6 py-4 rounded-2xl bg-white/5 border border-white/10 focus:border-gold outline-none font-bold text-white transition-all" onChange={e => setStudentInfo({...studentInfo, name: e.target.value})} />
            </div>
            <div className="grid grid-cols-2 gap-6">
               <div className="space-y-3">
                  <label className="text-[10px] font-black uppercase text-gray-500 tracking-widest">Academic Standard</label>
                  <input required placeholder="Class" className="w-full px-6 py-4 rounded-2xl bg-white/5 border border-white/10 focus:border-gold outline-none font-bold text-white transition-all" onChange={e => setStudentInfo({...studentInfo, standard: e.target.value})} />
               </div>
               <div className="space-y-3">
                  <label className="text-[10px] font-black uppercase text-gray-500 tracking-widest">Current Age</label>
                  <input required type="number" placeholder="Years" className="w-full px-6 py-4 rounded-2xl bg-white/5 border border-white/10 focus:border-gold outline-none font-bold text-white transition-all" onChange={e => setStudentInfo({...studentInfo, age: e.target.value})} />
               </div>
            </div>
            <div className="space-y-3">
               <label className="text-[10px] font-black uppercase text-gray-500 tracking-widest">Affiliated School</label>
               <input required placeholder="Institution name" className="w-full px-6 py-4 rounded-2xl bg-white/5 border border-white/10 focus:border-gold outline-none font-bold text-white transition-all" onChange={e => setStudentInfo({...studentInfo, school: e.target.value})} />
            </div>
            <button type="submit" className="w-full mt-6 bg-gold text-black font-black py-6 rounded-[2.5rem] shadow-2xl hover:scale-[1.02] transition-all uppercase tracking-widest text-xs">Verify & Initialize</button>
          </form>
        </div>
      </div>
    );
  }

  if (step === 'questions') {
    const q = filteredQuestions[currentQuestionIndex];
    if (!q) return <div className="p-32 text-center font-black text-gold animate-pulse">CALIBRATING BILINGUAL MODULE...</div>;

    return (
      <div className="max-w-6xl mx-auto px-6 py-20 animate-fade-in">
        <div className="mb-16 flex flex-col md:flex-row items-center justify-between gap-6">
          <div className="flex items-center space-x-4">
            <span className="text-[10px] font-black text-black bg-gold uppercase tracking-widest px-4 py-2 rounded-full">{selectedLevel}</span>
            <span className="text-xs font-bold text-gray-500 uppercase tracking-[0.2em]">Clinical Probe {currentQuestionIndex + 1} of {filteredQuestions.length}</span>
          </div>
          <div className="w-full md:w-64 bg-white/5 rounded-full h-2.5 overflow-hidden border border-white/5">
            <div className="bg-gold h-full transition-all duration-700 shadow-[0_0_15px_rgba(255,215,0,0.5)]" style={{ width: `${progress}%` }}></div>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-12 mb-20">
          <div className="bento-card p-12 border-white/10 shadow-2xl">
             <p className="text-[10px] font-black text-gold/40 uppercase tracking-widest mb-6">English Assessment Formulation</p>
             <h2 className="text-2xl md:text-3xl font-black text-white leading-tight tracking-tighter">{q.textEn}</h2>
          </div>
          <div className="bento-card p-12 border-gold/10 bg-gold/[0.02]">
             <p className="text-[10px] font-black text-gold/40 uppercase tracking-widest mb-6">Hindi Formulation (नीतिज्ञानम्)</p>
             <h2 className="text-2xl md:text-3xl font-hindi font-bold text-white leading-tight">{q.textHi}</h2>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
          {q.options.map(opt => (
            <button 
              key={opt.id} 
              onClick={() => handleAnswer(opt.indicator)} 
              className="bento-card p-10 text-left group border-white/5 hover:border-gold/30 hover:bg-gold/[0.03]"
            >
              <div className="flex items-start space-x-8">
                <div className="w-12 h-12 rounded-2xl bg-white/5 flex items-center justify-center font-black text-white/30 group-hover:bg-gold group-hover:text-black transition-all">
                  {opt.id.toUpperCase()}
                </div>
                <div className="flex-grow">
                  <p className="font-bold text-xl text-white mb-2 leading-snug group-hover:text-gold transition-colors">{opt.en}</p>
                  <p className="text-gray-500 font-hindi font-medium italic text-lg">{opt.hi}</p>
                </div>
              </div>
            </button>
          ))}
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-xl mx-auto px-6 py-32 text-center animate-fade-in">
      <div className="w-24 h-24 bg-gold text-black rounded-full flex items-center justify-center text-5xl mx-auto mb-12 gold-glow transform rotate-12">✓</div>
      <h2 className="text-5xl font-black text-white uppercase tracking-tighter mb-6">Diagnostic Complete</h2>
      <p className="text-gray-500 font-bold mb-16 leading-relaxed">The assessment has been securely logged for faculty review. Your well-being is our primary academic focus.</p>
      <button 
        onClick={() => window.location.reload()} 
        className="px-16 py-6 bg-white text-black rounded-[2.5rem] font-black uppercase tracking-widest text-xs shadow-2xl hover:bg-gold transition-all"
      >
        Close Portal
      </button>
    </div>
  );
};

