import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Quiz from './components/Quiz';
import AdminDashboard from './components/AdminDashboard';
import QuestionManager from './components/QuestionManager';
import Auth from './components/Auth';
import Hero from './components/Hero';
import { User, UserRole } from './types';
import { BRANDING } from './constants';

type AppView = 'home' | 'quiz' | 'login' | 'dashboard' | 'manager';

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<AppView>('home');
  const [user, setUser] = useState<User | null>(null);

  useEffect(() => {
    const savedUser = localStorage.getItem('ng_user_session');
    if (savedUser) setUser(JSON.parse(savedUser));
  }, []);

  const handleLogin = (u: User) => {
    setUser(u);
    localStorage.setItem('ng_user_session', JSON.stringify(u));
    setActiveView('dashboard');
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('ng_user_session');
    setActiveView('home');
  };

  const renderContent = () => {
    switch (activeView) {
      case 'home':
        return (
          <div>
            <Hero 
              onStartQuiz={() => setActiveView('quiz')} 
              onLogin={() => setActiveView('login')} 
            />

            {/* Bento Highlights Following Hero */}
            <section className="max-w-7xl mx-auto px-6 lg:px-8 py-24 border-t border-white/5">
               <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                  <div className="bento-card p-12 flex flex-col justify-end h-[450px] relative overflow-hidden group">
                     <div className="absolute top-12 right-12 text-8xl font-black text-white/5 group-hover:text-gold/10 transition-colors">01</div>
                     <h3 className="text-4xl font-black text-white mb-6 uppercase leading-none tracking-tighter">Bilingual <br />UI</h3>
                     <p className="text-gray-500 text-sm font-bold leading-relaxed">Native Devanagari support ensures linguistic comfort for deeper psychological disclosure.</p>
                  </div>
                  <div className="bento-card p-12 flex flex-col justify-end h-[450px] relative overflow-hidden group border-gold/20 bg-gold/[0.01]">
                     <div className="absolute top-12 right-12 text-8xl font-black text-white/5 group-hover:text-gold/10 transition-colors">02</div>
                     <h3 className="text-4xl font-black text-gold mb-6 uppercase leading-none tracking-tighter">Clinical <br />Scoring</h3>
                     <p className="text-gray-400 text-sm font-bold leading-relaxed">Advanced logic mapping behavioral signals into actionable risk tiers for faculty intervention.</p>
                  </div>
                  <div className="bento-card p-12 flex flex-col justify-end h-[450px] relative overflow-hidden group">
                     <div className="absolute top-12 right-12 text-8xl font-black text-white/5 group-hover:text-gold/10 transition-colors">03</div>
                     <h3 className="text-4xl font-black text-white mb-6 uppercase leading-none tracking-tighter">Secure <br />Reports</h3>
                     <p className="text-gray-500 text-sm font-bold leading-relaxed">Role-based access ensures sensitive clinical data remains protected within institution boundaries.</p>
                  </div>
               </div>
            </section>
          </div>
        );
      case 'quiz':
        return <Quiz onComplete={() => {}} />;
      case 'login':
        return <Auth onLogin={handleLogin} />;
      case 'dashboard':
        return user ? <AdminDashboard user={user} /> : <Auth onLogin={handleLogin} />;
      case 'manager':
        return user?.role === UserRole.ADMIN ? <QuestionManager /> : <Auth onLogin={handleLogin} />;
    }
  };

  return (
    <Layout activeView={activeView} onNavigate={setActiveView} user={user} onLogout={handleLogout}>
      {renderContent()}
    </Layout>
  );
};

export default App;

