import React, { useState, useMemo, useEffect } from 'react';
import { WellBeingLevel, Question, ResponseIndicator, StudentInfo, Submission } from '../types';
import { api } from '../services/api';

interface QuizProps {
  onComplete: (submission: Submission) => void;
}

type QuizStep = 'level-select' | 'student-info' | 'questions' | 'completed';

const Quiz: React.FC<QuizProps> = ({ onComplete }) => {
  const [step, setStep] = useState<QuizStep>('level-select');
  const [questions, setQuestions] = useState<Question[]>([]);
  const [selectedLevel, setSelectedLevel] = useState<WellBeingLevel | null>(null);
  const [studentInfo, setStudentInfo] = useState<StudentInfo>({ name: '', age: '', standard: '', school: '' });
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [answers, setAnswers] = useState<{ [id: string]: ResponseIndicator }>({});

  useEffect(() => {
    setQuestions(api.fetchQuestions());
  }, []);

  const filteredQuestions = useMemo(() => {
    return questions.filter(q => q.level === selectedLevel);
  }, [selectedLevel, questions]);

  const progress = filteredQuestions.length > 0 
    ? Math.round(((currentQuestionIndex) / filteredQuestions.length) * 100) 
    : 0;

  const handleAnswer = (indicator: ResponseIndicator) => {
    const questionId = filteredQuestions[currentQuestionIndex].id;
    const newAnswers = { ...answers, [questionId]: indicator };
    setAnswers(newAnswers);

    if (currentQuestionIndex < filteredQuestions.length - 1) {
      setCurrentQuestionIndex(prev => prev + 1);
    } else {
      const answerList = Object.values(newAnswers);
      const { riskStatus, conclusion } = api.analyzeResults(answerList);

      const submission: Submission = {
        id: `sub_${Math.random().toString(36).substr(2, 9)}`,
        student: studentInfo,
        level: selectedLevel!,
        answers: newAnswers,
        metrics: {
          healthyCount: answerList.filter(v => v === ResponseIndicator.HEALTHY).length,
          concernCount: answerList.filter(v => v === ResponseIndicator.CONCERN).length,
          redFlagCount: answerList.filter(v => v === ResponseIndicator.RED_FLAG).length,
          totalQuestions: answerList.length
        },
        riskStatus,
        conclusion,
        timestamp: Date.now(),
      };

      api.submitAssessment(submission);
      onComplete(submission);
      setStep('completed');
    }
  };

  if (step === 'level-select') {
    return (
      <div className="max-w-5xl mx-auto px-6 py-24">
        <div className="text-center mb-16">
          <h2 className="text-5xl font-black text-charcoal tracking-tighter uppercase mb-6">Select Assessment Tier</h2>
          <p className="text-gray-400 font-bold uppercase tracking-widest text-xs">Developmentally tailored diagnostic modules</p>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
          {Object.values(WellBeingLevel).map((level) => (
            <button
              key={level}
              onClick={() => { setSelectedLevel(level); setStep('student-info'); }}
              className="bento-item p-12 text-left group border-gray-100 rounded-[3rem]"
            >
              <div className="flex items-center justify-between">
                <div>
                  <h3 className="text-3xl font-black text-charcoal group-hover:text-gold transition-colors tracking-tighter">{level}</h3>
                  <p className="text-[10px] font-black text-gray-400 uppercase tracking-[0.2em] mt-3">Psychological Baseline Probe</p>
                </div>
                <div className="w-16 h-16 rounded-3xl bg-softGray flex items-center justify-center text-gray-300 group-hover:bg-gold group-hover:text-charcoal transition-all">
                  <span className="text-3xl font-bold">→</span>
                </div>
              </div>
            </button>
          ))}
        </div>
      </div>
    );
  }

  if (step === 'student-info') {
    return (
      <div className="max-w-2xl mx-auto px-6 py-24">
        <div className="glass-card p-12 shadow-soft-xl border-white">
          <h2 className="text-3xl font-black text-charcoal tracking-tighter uppercase mb-10 text-center">Identity Verification</h2>
          <form onSubmit={e => { e.preventDefault(); setStep('questions'); }} className="space-y-8">
            <div className="space-y-3">
               <label className="text-[10px] font-black uppercase text-gray-400 tracking-widest px-1">Full Legal Name</label>
               <input required placeholder="Enter student name" className="w-full px-8 py-5 rounded-[2rem] bg-softGray border border-transparent focus:bg-white focus:border-gold outline-none font-bold text-charcoal transition-all" onChange={e => setStudentInfo({...studentInfo, name: e.target.value})} />
            </div>
            <div className="grid grid-cols-2 gap-8">
               <div className="space-y-3">
                  <label className="text-[10px] font-black uppercase text-gray-400 tracking-widest px-1">Standard</label>
                  <input required placeholder="Class" className="w-full px-8 py-5 rounded-[2rem] bg-softGray border border-transparent focus:bg-white focus:border-gold outline-none font-bold text-charcoal transition-all" onChange={e => setStudentInfo({...studentInfo, standard: e.target.value})} />
               </div>
               <div className="space-y-3">
                  <label className="text-[10px] font-black uppercase text-gray-400 tracking-widest px-1">Age</label>
                  <input required type="number" placeholder="Years" className="w-full px-8 py-5 rounded-[2rem] bg-softGray border border-transparent focus:bg-white focus:border-gold outline-none font-bold text-charcoal transition-all" onChange={e => setStudentInfo({...studentInfo, age: e.target.value})} />
