            <div className="space-y-3">
               <label className="text-[10px] font-black uppercase text-gray-400 tracking-widest px-1">Affiliated School</label>
               <input required placeholder="Institution name" className="w-full px-8 py-5 rounded-[2rem] bg-softGray border border-transparent focus:bg-white focus:border-gold outline-none font-bold text-charcoal transition-all" onChange={e => setStudentInfo({...studentInfo, school: e.target.value})} />
            </div>
            <button type="submit" className="w-full mt-6 bg-gold text-charcoal font-black py-6 rounded-full shadow-lg hover:shadow-gold/20 transition-all uppercase tracking-[0.2em] text-[11px]">Verify & Initialize</button>
          </form>
        </div>
      </div>
    );
  }

  if (step === 'questions') {
    const q = filteredQuestions[currentQuestionIndex];
    if (!q) return <div className="p-32 text-center font-black text-gold animate-pulse">CALIBRATING BILINGUAL MODULE...</div>;

    return (
      <div className="max-w-6xl mx-auto px-6 py-20">
        <div className="mb-16 flex flex-col md:flex-row items-center justify-between gap-8">
          <div className="flex items-center space-x-6">
            <span className="text-[11px] font-black text-charcoal bg-gold uppercase tracking-[0.2em] px-6 py-2.5 rounded-full shadow-sm">{selectedLevel}</span>
            <span className="text-xs font-bold text-gray-400 uppercase tracking-[0.3em]">Module {currentQuestionIndex + 1} / {filteredQuestions.length}</span>
          </div>
          <div className="w-full md:w-80 bg-gray-100 rounded-full h-2.5 overflow-hidden">
            <div className="bg-gold h-full transition-all duration-700 shadow-sm" style={{ width: `${progress}%` }}></div>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-12 mb-20">
          <div className="bento-item p-12 rounded-[3rem] shadow-sm">
             <p className="text-[11px] font-black text-gold uppercase tracking-widest mb-6 border-b border-gray-50 pb-4">English Formulation</p>
             <h2 className="text-3xl font-black text-charcoal leading-tight tracking-tighter">{q.textEn}</h2>
          </div>
          <div className="bento-item p-12 rounded-[3rem] border-gold/10 bg-gold/[0.02] shadow-sm">
             <p className="text-[11px] font-black text-gold uppercase tracking-widest mb-6 border-b border-gold/10 pb-4">हिंदी अनुवाद (Rozha One)</p>
             <h2 className="text-3xl font-hindi font-bold text-charcoal leading-tight">{q.textHi}</h2>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
          {q.options.map(opt => (
            <button 
              key={opt.id} 
              onClick={() => handleAnswer(opt.indicator)} 
              className="bento-item p-10 text-left group rounded-[2.5rem]"
            >
              <div className="flex items-center space-x-8">
                <div className="w-14 h-14 rounded-2xl bg-softGray flex items-center justify-center font-black text-gray-400 group-hover:bg-gold group-hover:text-charcoal transition-all text-lg">
                  {opt.id.toUpperCase()}
                </div>
                <div className="flex-grow">
                  <p className="font-bold text-xl text-charcoal mb-1 group-hover:text-gold transition-colors">{opt.en}</p>
                  <p className="text-gray-400 font-hindi font-medium italic text-lg">{opt.hi}</p>
                </div>
              </div>
            </button>
          ))}
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-2xl mx-auto px-6 py-32 text-center">
      <div className="w-24 h-24 bg-gold text-charcoal rounded-full flex items-center justify-center text-4xl mx-auto mb-12 shadow-neon-gold transform rotate-12">✓</div>
      <h2 className="text-5xl font-black text-charcoal uppercase tracking-tighter mb-6">Diagnostic Complete</h2>
      <p className="text-gray-400 font-medium mb-16 text-lg">The clinical screening session has been successfully finalized. All diagnostic markers are securely synchronized with the institutional dashboard.</p>
      <button 
        onClick={() => window.location.reload()} 
        className="px-20 py-8 bg-charcoal text-white rounded-full font-black uppercase tracking-[0.2em] text-[13px] shadow-2xl hover:bg-black transition-all"
      >
        Return to Portal
      </button>
    </div>
  );
};

