import React, { useState, useEffect } from 'react';
import { Submission, UserRole, User } from '../types';
import { api } from '../services/api';

interface AdminDashboardProps {
  user: User;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ user }) => {
  const [submissions, setSubmissions] = useState<Submission[]>([]);
  const [filter, setFilter] = useState<'all' | 'CRITICAL'>('all');

  useEffect(() => {
    setSubmissions(api.fetchSubmissions());
  }, []);

  const filteredData = submissions.filter(s => 
    filter === 'all' ? true : s.riskStatus === 'CRITICAL'
  );

  const stats = {
    total: submissions.length,
    critical: submissions.filter(s => s.riskStatus === 'CRITICAL').length,
    moderate: submissions.filter(s => s.riskStatus === 'MODERATE').length,
    stable: submissions.filter(s => s.riskStatus === 'STABLE').length,
  };

  return (
    <div className="max-w-7xl mx-auto px-6 lg:px-8 py-20">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-end mb-16 gap-8">
        <div>
          <h2 className="text-5xl font-black text-charcoal tracking-tighter uppercase leading-none">
            {user.role === UserRole.ADMIN ? 'Command Center' : 'Review Portal'}
          </h2>
          <p className="text-gray-400 font-medium mt-3 text-lg">Active Institutional Identity: <span className="text-gold font-black">{user.username}</span></p>
        </div>
        <div className="flex bg-white shadow-sm border border-gray-100 p-2 rounded-full">
          <button 
            onClick={() => setFilter('all')}
            className={`px-8 py-3 rounded-full text-[11px] font-black uppercase tracking-widest transition-all ${filter === 'all' ? 'bg-gold text-charcoal shadow-md' : 'text-gray-400 hover:text-charcoal'}`}
          >
            All Sessions
          </button>
          <button 
            onClick={() => setFilter('CRITICAL')}
            className={`px-8 py-3 rounded-full text-[11px] font-black uppercase tracking-widest transition-all ${filter === 'CRITICAL' ? 'bg-red-500 text-white shadow-md' : 'text-gray-400 hover:text-red-500'}`}
          >
            Critical Flags
          </button>
        </div>
      </div>

      {/* Metrics Grid */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-8 mb-16">
        <div className="bg-white p-10 rounded-[2.5rem] shadow-sm border border-gray-50 group hover:border-gold transition-all">
          <p className="text-[10px] font-black text-gray-400 uppercase tracking-[0.3em]">Screenings</p>
          <p className="text-5xl font-black text-charcoal mt-3 tracking-tighter">{stats.total}</p>
        </div>
        <div className="bg-emerald-50 p-10 rounded-[2.5rem] border border-emerald-100/50 group hover:shadow-lg transition-all">
          <p className="text-[10px] font-black text-emerald-600 uppercase tracking-[0.3em]">Stable</p>
          <p className="text-5xl font-black text-emerald-700 mt-3 tracking-tighter">{stats.stable}</p>
        </div>
        <div className="bg-amber-50 p-10 rounded-[2.5rem] border border-amber-100/50 group hover:shadow-lg transition-all">
          <p className="text-[10px] font-black text-amber-600 uppercase tracking-[0.3em]">Moderate</p>
          <p className="text-5xl font-black text-amber-700 mt-3 tracking-tighter">{stats.moderate}</p>
        </div>
        <div className="bg-red-50 p-10 rounded-[2.5rem] border border-red-100 group hover:shadow-red-100 shadow-xl transition-all">
          <p className="text-[10px] font-black text-red-600 uppercase tracking-[0.3em]">Alerts</p>
          <p className="text-5xl font-black text-red-700 mt-3 tracking-tighter">{stats.critical}</p>
        </div>
      </div>

      <div className="bg-white rounded-[3rem] overflow-hidden border border-gray-100 shadow-soft-xl">
        <div className="overflow-x-auto">
          <table className="min-w-full divide-y divide-gray-50">
            <thead>
              <tr className="bg-gray-50/50">
                <th className="px-10 py-8 text-left text-[11px] font-black text-gray-400 uppercase tracking-[0.3em]">Identity & Institution</th>
                <th className="px-10 py-8 text-left text-[11px] font-black text-gray-400 uppercase tracking-[0.3em]">Risk Profile</th>
                <th className="px-10 py-8 text-left text-[11px] font-black text-gray-400 uppercase tracking-[0.3em]">Clinical Log</th>
                <th className="px-10 py-8 text-left text-[11px] font-black text-gray-400 uppercase tracking-[0.3em]">Sync Date</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-50">
              {filteredData.length === 0 ? (
                <tr>
                  <td colSpan={4} className="px-10 py-32 text-center text-gray-300 font-black uppercase tracking-[0.4em] text-sm">Synchronizing Data Records...</td>
                </tr>
              ) : (
                filteredData.map((s) => (
                  <tr key={s.id} className="hover:bg-gray-50/30 transition-colors group">
                    <td className="px-10 py-10">
                      <div className="text-xl font-black text-charcoal tracking-tighter group-hover:text-gold transition-colors">{s.student.name}</div>
                      <div className="text-[10px] text-gray-400 font-black uppercase mt-1.5 tracking-widest">Std {s.student.standard} | {s.student.school}</div>
                    </td>
                    <td className="px-10 py-10">
                      <div className={`inline-flex items-center space-x-3 px-6 py-2.5 rounded-full border ${
                        s.riskStatus === 'CRITICAL' ? 'bg-red-50 text-red-700 border-red-100' : 
                        s.riskStatus === 'MODERATE' ? 'bg-amber-50 text-amber-700 border-amber-100' : 'bg-emerald-50 text-emerald-700 border-emerald-100'
                      }`}>
                        <span className={`w-2 h-2 rounded-full animate-pulse ${
                          s.riskStatus === 'CRITICAL' ? 'bg-red-600' : 
                          s.riskStatus === 'MODERATE' ? 'bg-amber-600' : 'bg-emerald-600'
                        }`} />
                        <span className="text-[11px] font-black uppercase tracking-widest">{s.riskStatus}</span>
                      </div>
                    </td>
                    <td className="px-10 py-10">
                      <p className="text-sm text-gray-600 leading-relaxed font-medium max-w-md italic">
                        "{s.conclusion}"
                      </p>
                    </td>
                    <td className="px-10 py-10 text-[11px] text-gray-300 font-black uppercase tracking-tighter">
                      {new Date(s.timestamp).toLocaleDateString()}
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default AdminDashboard;

