import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import Layout from './components/Layout';
import Quiz from './components/Quiz';
import AdminDashboard from './components/AdminDashboard';
import QuestionManager from './components/QuestionManager';
import Auth from './components/Auth';
import Hero from './components/Hero';
import { User, UserRole, WellBeingLevel } from './types';

type AppView = 'home' | 'quiz' | 'login' | 'dashboard' | 'manager';

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<AppView>('home');
  const [user, setUser] = useState<User | null>(null);

  useEffect(() => {
    const savedUser = localStorage.getItem('ng_user_session');
    if (savedUser) setUser(JSON.parse(savedUser));
  }, []);

  const handleLogin = (u: User) => {
    setUser(u);
    localStorage.setItem('ng_user_session', JSON.stringify(u));
    setActiveView('dashboard');
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('ng_user_session');
    setActiveView('home');
  };

  const levels = [
    { title: WellBeingLevel.LEVEL_1, hindi: 'कक्षा १ से ३', icon: '🌱', desc: 'Foundational Discovery Module', shadow: 'rgba(52, 211, 153, 0.2)' },
    { title: WellBeingLevel.LEVEL_2, hindi: 'कक्षा ४ से ६', icon: '🌿', desc: 'Primary Development Probe', shadow: 'rgba(16, 185, 129, 0.2)' },
    { title: WellBeingLevel.LEVEL_3, hindi: 'कक्षा ७ से ८', icon: '🌳', desc: 'Resilience & Growth Metric', shadow: 'rgba(5, 150, 105, 0.2)' },
    { title: WellBeingLevel.LEVEL_4, hindi: 'कक्षा ९ से १०', icon: '🌲', desc: 'Advanced Academic Readiness', shadow: 'rgba(4, 120, 87, 0.2)' },
  ];

  const renderContent = () => {
    switch (activeView) {
      case 'home':
        return (
          <div className="pb-32">
            <Hero 
              onStartQuiz={() => setActiveView('quiz')} 
              onLogin={() => setActiveView('login')} 
            />

            <section className="max-w-7xl mx-auto px-6 py-40">
              <div className="text-center mb-24 space-y-4">
                <motion.span 
                  initial={{ opacity: 0 }}
                  whileInView={{ opacity: 1 }}
                  className="text-gold text-[10px] font-black uppercase tracking-[0.5em] block"
                >
                  Diagnostic Framework
                </motion.span>
                <motion.h3 
                  initial={{ opacity: 0, y: 30 }}
                  whileInView={{ opacity: 1, y: 0 }}
                  className="text-4xl md:text-6xl font-black text-charcoal uppercase tracking-tighter"
                >
                  Select Your Tier
                </motion.h3>
                <motion.p 
                  initial={{ opacity: 0 }}
                  whileInView={{ opacity: 0.6 }}
                  className="text-gray-400 font-hindi text-xl md:text-2xl"
                >
                  छात्रों के मानसिक स्वास्थ्य हेतु स्तर-आधारित मॉड्यूल
                </motion.p>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
                {levels.map((lvl, i) => (
                  <motion.div
                    key={i}
                    initial={{ opacity: 0, y: 30 }}
                    whileInView={{ opacity: 1, y: 0 }}
                    transition={{ delay: i * 0.1, duration: 0.6 }}
                    viewport={{ once: true }}
                    whileHover={{ y: -10 }}
                    onClick={() => setActiveView('quiz')}
                    className="bento-item p-10 rounded-[3rem] cursor-pointer group flex flex-col items-center text-center hover:shadow-neon-gold border-white shadow-soft-xl"
                  >
                    <div className="text-7xl mb-10 transform group-hover:scale-125 transition-all duration-500 drop-shadow-lg">
                      {lvl.icon}
                    </div>
                    <h4 className="text-2xl font-black text-charcoal mb-2 uppercase tracking-tighter group-hover:text-gold transition-colors">
                      {lvl.title}
                    </h4>
                    <p className="text-gray-400 font-hindi text-lg mb-8 italic opacity-80 group-hover:opacity-100 transition-opacity">
                      {lvl.hindi}
                    </p>
                    <div className="flex-grow">
                      <p className="text-[10px] text-gray-400 font-bold uppercase tracking-[0.2em] leading-relaxed">
                        {lvl.desc}
                      </p>
                    </div>
                    <div className="mt-10 w-12 h-12 rounded-full bg-softGray flex items-center justify-center text-charcoal/20 group-hover:bg-gold group-hover:text-charcoal transition-all">
                      <span className="text-xl font-bold">→</span>
                    </div>
                  </motion.div>
                ))}
              </div>
            </section>
          </div>
        );
      case 'quiz':
        return <Quiz onComplete={() => setActiveView('home')} />;
      case 'login':
        return <Auth onLogin={handleLogin} />;
      case 'dashboard':
        return user ? <AdminDashboard user={user} /> : <Auth onLogin={handleLogin} />;
      case 'manager':
        return user?.role === UserRole.ADMIN ? <QuestionManager /> : <Auth onLogin={handleLogin} />;
      default:
        return null;
    }
  };

  return (
    <Layout activeView={activeView} onNavigate={setActiveView} user={user} onLogout={handleLogout}>
      {renderContent()}
    </Layout>
  );
};

export default App;

