/**
 * NITGYANAM WELL-BEING PORTAL - TECHNICAL ARCHITECTURE
 * ---------------------------------------------------
 * Framework: React 19 (Functional Components + Hooks)
 * Styling: Tailwind CSS (Utility-first, JIT Engine)
 * Animation: Framer Motion (Declarative Orchestration)
 * State Management: Local React State + LocalStorage Persistence
 * Data Flow: Unidirectional (Parent-to-Child via Props)
 * 
 * CORE MODULES:
 * 1. Hero: Parallax-driven entry point using useScroll hooks.
 * 2. Quiz: Finite State Machine (Level -> Info -> Questions -> Result).
 * 3. Admin: Data-aggregation layer with real-time filtering.
 * 4. API Service: Mock-backend wrapper for browser storage.
 */

import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import Layout from './components/Layout';
import Quiz from './components/Quiz';
import AdminDashboard from './components/AdminDashboard';
import QuestionManager from './components/QuestionManager';
import Auth from './components/Auth';
import Hero from './components/Hero';
import { User, UserRole, WellBeingLevel } from './types';

type AppView = 'home' | 'quiz' | 'login' | 'dashboard' | 'manager';

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<AppView>('home');
  const [user, setUser] = useState<User | null>(null);

  useEffect(() => {
    const savedUser = localStorage.getItem('ng_user_session');
    if (savedUser) setUser(JSON.parse(savedUser));
  }, []);

  const handleLogin = (u: User) => {
    setUser(u);
    localStorage.setItem('ng_user_session', JSON.stringify(u));
    setActiveView('dashboard');
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('ng_user_session');
    setActiveView('home');
  };

  const levels = [
    { title: WellBeingLevel.LEVEL_1, hindi: 'कक्षा १ से ३', icon: '🎨', desc: 'Emotions & Home Metaphors', color: 'text-wellBeingBlue' },
    { title: WellBeingLevel.LEVEL_2, hindi: 'कक्षा ४ से ६', icon: '🔋', desc: 'Energy & Focus Probe', color: 'text-wellBeingGreen' },
    { title: WellBeingLevel.LEVEL_3, hindi: 'कक्षा ७ से ८', icon: '📱', desc: 'Identity & Social Connection', color: 'text-wellBeingBlue' },
    { title: WellBeingLevel.LEVEL_4, hindi: 'कक्षा ९ से १०', icon: '🚀', desc: 'Aspirations & Future Dread', color: 'text-slate-800' },
  ];

  const renderContent = () => {
    switch (activeView) {
      case 'home':
        return (
          <div className="pb-32">
            <Hero 
              onStartQuiz={() => setActiveView('quiz')} 
              onLogin={() => setActiveView('login')} 
            />

            <section className="max-w-7xl mx-auto px-6 py-40">
              <div className="text-center mb-24 space-y-4">
                <motion.span 
                  initial={{ opacity: 0 }}
                  whileInView={{ opacity: 1 }}
                  className="text-wellBeingBlue text-[10px] font-black uppercase tracking-[0.5em] block"
                >
                  Diagnostic Modules
                </motion.span>
                <motion.h3 
                  initial={{ opacity: 0, y: 30 }}
                  whileInView={{ opacity: 1, y: 0 }}
                  className="text-4xl md:text-6xl font-black text-slate-800 uppercase tracking-tighter"
                >
                  Assessment Tiers
                </motion.h3>
                <motion.p 
                  initial={{ opacity: 0 }}
                  whileInView={{ opacity: 0.6 }}
                  className="text-slate-400 font-hindi text-xl md:text-2xl"
                >
                  छात्रों के मानसिक स्वास्थ्य हेतु स्तर-आधारित मॉड्यूल
                </motion.p>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-10">
                {levels.map((lvl, i) => (
                  <motion.div
                    key={i}
                    initial={{ opacity: 0, y: 30 }}
                    whileInView={{ opacity: 1, y: 0 }}
                    transition={{ delay: i * 0.1, duration: 0.6 }}
                    viewport={{ once: true }}
                    whileHover={{ y: -15, scale: 1.02 }}
                    onClick={() => setActiveView('quiz')}
                    className="bg-white p-12 rounded-[4rem] cursor-pointer group flex flex-col items-center text-center shadow-bento hover:shadow-2xl hover:border-wellBeingBlue border border-transparent transition-all"
                  >
                    <div className={`text-7xl mb-10 transform group-hover:scale-125 transition-all duration-500 drop-shadow-md`}>
                      {lvl.icon}
                    </div>
                    <h4 className={`text-2xl font-black mb-2 uppercase tracking-tighter group-hover:text-wellBeingBlue transition-colors ${lvl.color}`}>
                      {lvl.title}
                    </h4>
                    <p className="text-slate-400 font-hindi text-lg mb-8 italic opacity-80 group-hover:opacity-100 transition-opacity">
                      {lvl.hindi}
                    </p>
                    <div className="flex-grow">
                      <p className="text-[10px] text-slate-400 font-bold uppercase tracking-[0.2em] leading-relaxed">
                        {lvl.desc}
                      </p>
                    </div>
                    <div className="mt-12 w-14 h-14 rounded-full bg-slate-50 flex items-center justify-center text-wellBeingBlue/30 group-hover:bg-wellBeingBlue group-hover:text-white transition-all shadow-sm">
                      <span className="text-xl font-bold">→</span>
                    </div>
                  </motion.div>
                ))}
              </div>
            </section>
          </div>
        );
      case 'quiz':
        return <Quiz onComplete={() => setActiveView('home')} />;
      case 'login':
        return <Auth onLogin={handleLogin} />;
      case 'dashboard':
        return user ? <AdminDashboard user={user} /> : <Auth onLogin={handleLogin} />;
      case 'manager':
        return user?.role === UserRole.ADMIN ? <QuestionManager /> : <Auth onLogin={handleLogin} />;
      default:
        return null;
    }
  };

  return (
    <Layout activeView={activeView} onNavigate={setActiveView} user={user} onLogout={handleLogout}>
      {renderContent()}
    </Layout>
  );
};

export default App;

import { Question, Submission, ResponseIndicator, WellBeingLevel } from '../types';
import { QUIZ_DATA } from '../constants';

const QUESTIONS_KEY = 'nit_gyanam_questions_v2';
const SUBMISSIONS_KEY = 'nit_gyanam_submissions_v2';

// Simulated network delay to mimic a real database connection
const delay = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

export const api = {
  /**
   * FETCH QUESTIONS
   * In a real DB: This would be: return fetch('/api/questions').then(res => res.json());
   */
  fetchQuestions: async (): Promise<Question[]> => {
    await delay(600); // Simulate network latency
    const saved = localStorage.getItem(QUESTIONS_KEY);
    if (!saved) {
      localStorage.setItem(QUESTIONS_KEY, JSON.stringify(QUIZ_DATA));
      return QUIZ_DATA;
    }
    return JSON.parse(saved);
  },

  /**
   * SAVE QUESTIONS
   * In a real DB: This would be a POST or PUT request to your API.
   */
  saveQuestions: async (questions: Question[]): Promise<void> => {
    await delay(800);
    localStorage.setItem(QUESTIONS_KEY, JSON.stringify(questions));
  },

  /**
   * SUBMIT ASSESSMENT
   * In a real DB: This would send the student's data to a permanent cloud store.
   */
  submitAssessment: async (submission: Submission): Promise<Submission> => {
    await delay(1200); // Simulate processing time
    const saved = localStorage.getItem(SUBMISSIONS_KEY);
    const submissions: Submission[] = saved ? JSON.parse(saved) : [];
    submissions.unshift(submission);
    localStorage.setItem(SUBMISSIONS_KEY, JSON.stringify(submissions));
    return submission;
  },

  /**
   * FETCH SUBMISSIONS
   * In a real DB: This would query your database for all student records.
   */
  fetchSubmissions: async (): Promise<Submission[]> => {
    await delay(700);
    const saved = localStorage.getItem(SUBMISSIONS_KEY);
    return saved ? JSON.parse(saved) : [];
  },

  analyzeResults: (answers: ResponseIndicator[]) => {
    const total = answers.length;
    const redFlagCount = answers.filter(a => a === ResponseIndicator.RED_FLAG).length;
    const concernCount = answers.filter(a => a === ResponseIndicator.CONCERN).length;
    const healthyCount = answers.filter(a => a === ResponseIndicator.HEALTHY).length;

    const redFlagPct = (redFlagCount / total) * 100;

    if (redFlagPct >= 10) {
      return {
        riskStatus: 'CRITICAL' as const,
        conclusion: 'URGENT INTERVENTION REQUIRED. The student has triggered high-risk psychological markers. Immediate physical intervention and parent/counselor notification are recommended.'
      };
    } else if (concernCount > healthyCount || concernCount > (total * 0.3)) {
      return {
        riskStatus: 'MODERATE' as const,
        conclusion: 'MODERATE STRESS DETECTED. The student shows persistent indicators of anxiety or emotional fatigue. Recommend academic workload review and school counseling sessions.'
      };
    } else {
      return {
        riskStatus: 'STABLE' as const,
        conclusion: 'STUDENT APPEARS STABLE. Responses indicate a healthy adjustment to academic and social environment. Continue regular monitoring.'
      };
    }
  }
};

