import React, { useState, useMemo, useEffect } from 'react';
import { WellBeingLevel, Question, ResponseIndicator, StudentInfo, Submission } from '../types';
import { api } from '../services/api';

interface QuizProps {
  onComplete: (submission: Submission) => void;
}

type QuizStep = 'level-select' | 'student-info' | 'questions' | 'syncing' | 'completed';

const Quiz: React.FC<QuizProps> = ({ onComplete }) => {
  const [step, setStep] = useState<QuizStep>('level-select');
  const [questions, setQuestions] = useState<Question[]>([]);
  const [selectedLevel, setSelectedLevel] = useState<WellBeingLevel | null>(null);
  const [studentInfo, setStudentInfo] = useState<StudentInfo>({ name: '', age: '', standard: '', school: '' });
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [answers, setAnswers] = useState<{ [id: string]: ResponseIndicator }>({});

  useEffect(() => {
    const loadQuestions = async () => {
      const data = await api.fetchQuestions();
      setQuestions(data);
    };
    loadQuestions();
  }, []);

  const filteredQuestions = useMemo(() => {
    return questions.filter(q => q.level === selectedLevel);
  }, [selectedLevel, questions]);

  const progress = filteredQuestions.length > 0 
    ? Math.round(((currentQuestionIndex) / filteredQuestions.length) * 100) 
    : 0;

  const handleAnswer = async (indicator: ResponseIndicator) => {
    const questionId = filteredQuestions[currentQuestionIndex].id;
    const newAnswers = { ...answers, [questionId]: indicator };
    setAnswers(newAnswers);

    if (currentQuestionIndex < filteredQuestions.length - 1) {
      setCurrentQuestionIndex(prev => prev + 1);
    } else {
      setStep('syncing');
      const answerList = Object.values(newAnswers);
      const { riskStatus, conclusion } = api.analyzeResults(answerList);

      const submission: Submission = {
        id: `sub_${Math.random().toString(36).substr(2, 9)}`,
        student: studentInfo,
        level: selectedLevel!,
        answers: newAnswers,
        metrics: {
          healthyCount: answerList.filter(v => v === ResponseIndicator.HEALTHY).length,
          concernCount: answerList.filter(v => v === ResponseIndicator.CONCERN).length,
          redFlagCount: answerList.filter(v => v === ResponseIndicator.RED_FLAG).length,
          totalQuestions: answerList.length
        },
        riskStatus,
        conclusion,
        timestamp: Date.now(),
      };

      await api.submitAssessment(submission);
      onComplete(submission);
      setStep('completed');
    }
  };

  if (step === 'syncing') {
    return (
      <div className="max-w-2xl mx-auto px-6 py-40 text-center">
        <div className="w-20 h-20 border-4 border-wellBeingGreen border-t-transparent rounded-full animate-spin mx-auto mb-10"></div>
        <h2 className="text-3xl font-black text-slate-800 uppercase tracking-tighter mb-4">Securing Data</h2>
        <p className="text-slate-400 font-bold uppercase tracking-[0.3em] text-[10px]">Uploading results to NitGyanam Cloud...</p>
      </div>
    );
  }

  if (step === 'level-select') {
    return (
      <div className="max-w-5xl mx-auto px-6 py-24">
        <div className="text-center mb-16">
          <h2 className="text-4xl md:text-5xl font-black text-wellBeingBlue tracking-tighter uppercase mb-6">Select Your Grade</h2>
          <p className="text-slate-400 font-bold uppercase tracking-widest text-xs">Choose the tier that fits your standard</p>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
          {Object.values(WellBeingLevel).map((level) => (
            <button
              key={level}
              onClick={() => { setSelectedLevel(level); setStep('student-info'); }}
              className="bg-white p-12 text-left group border border-slate-100 rounded-[3rem] hover:border-wellBeingBlue transition-all shadow-bento hover:shadow-xl"
            >
              <div className="flex items-center justify-between">
                <div>
                  <h3 className="text-3xl font-black text-slate-800 group-hover:text-wellBeingBlue transition-colors tracking-tighter">{level}</h3>
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mt-3">Interactive Self-Check</p>
                </div>
                <div className="w-16 h-16 rounded-full bg-slate-50 flex items-center justify-center text-slate-300 group-hover:bg-wellBeingBlue group-hover:text-white transition-all">
                  <span className="text-3xl font-bold">→</span>
                </div>
              </div>
            </button>
          ))}
        </div>
      </div>
    );
  }

  if (step === 'student-info') {
    return (
      <div className="max-w-2xl mx-auto px-6 py-24">
        <div className="bg-white p-12 shadow-soft-xl rounded-[3rem] border border-slate-100">
          <h2 className="text-3xl font-black text-slate-800 tracking-tighter uppercase mb-10 text-center">Student Details</h2>
          <form onSubmit={e => { e.preventDefault(); setStep('questions'); }} className="space-y-8">
            <div className="space-y-3">
               <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest px-1">Full Name</label>
               <input required placeholder="Student Name" className="w-full px-8 py-5 rounded-[2rem] bg-slate-50 border border-transparent focus:bg-white focus:border-wellBeingBlue outline-none font-bold text-slate-800 transition-all" onChange={e => setStudentInfo({...studentInfo, name: e.target.value})} />
            </div>
            <div className="grid grid-cols-2 gap-8">
               <div className="space-y-3">
                  <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest px-1">Standard</label>
                  <input required placeholder="Class" className="w-full px-8 py-5 rounded-[2rem] bg-slate-50 border border-transparent focus:bg-white focus:border-wellBeingBlue outline-none font-bold text-slate-800 transition-all" onChange={e => setStudentInfo({...studentInfo, standard: e.target.value})} />
               </div>
               <div className="space-y-3">
                  <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest px-1">Age</label>
                  <input required type="number" placeholder="Age" className="w-full px-8 py-5 rounded-[2rem] bg-slate-50 border border-transparent focus:bg-white focus:border-wellBeingBlue outline-none font-bold text-slate-800 transition-all" onChange={e => setStudentInfo({...studentInfo, age: e.target.value})} />
               </div>
            </div>
            <div className="space-y-3">
               <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest px-1">School Name</label>
               <input required placeholder="Enter School" className="w-full px-8 py-5 rounded-[2rem] bg-slate-50 border border-transparent focus:bg-white focus:border-wellBeingBlue outline-none font-bold text-slate-800 transition-all" onChange={e => setStudentInfo({...studentInfo, school: e.target.value})} />
            </div>
            <button type="submit" className="w-full mt-6 bg-wellBeingBlue text-white font-black py-6 rounded-full shadow-lg hover:shadow-wellBeingBlue/20 transition-all uppercase tracking-[0.2em] text-[11px]">Begin Diagnostic</button>
          </form>
        </div>
      </div>
    );
  }

  if (step === 'questions') {
    const q = filteredQuestions[currentQuestionIndex];
    if (!q) return <div className="p-32 text-center font-black text-wellBeingBlue animate-pulse">Initializing Assessment...</div>;

    return (
      <div className="max-w-6xl mx-auto px-6 py-20">
        <div className="mb-16 flex flex-col md:flex-row items-center justify-between gap-8">
          <div className="flex items-center space-x-6">
            <span className="text-[11px] font-black text-white bg-wellBeingBlue uppercase tracking-[0.2em] px-6 py-2.5 rounded-full shadow-sm">{selectedLevel}</span>
            <span className="text-xs font-bold text-slate-400 uppercase tracking-[0.3em]">Module {currentQuestionIndex + 1} / {filteredQuestions.length}</span>
          </div>
          <div className="w-full md:w-80 bg-slate-200 rounded-full h-3 overflow-hidden">
            <div className="bg-wellBeingGreen h-full transition-all duration-700" style={{ width: `${progress}%` }}></div>
          </div>
        </div>

        <div className="bg-white p-12 md:p-16 rounded-[4rem] border border-slate-100 shadow-bento mb-16 text-center">
             <h2 className="text-3xl md:text-4xl font-black text-slate-800 leading-tight tracking-tighter mb-8">{q.textEn}</h2>
             <div className="w-20 h-1 bg-wellBeingGreen/20 mx-auto mb-8"></div>
             <h2 className="text-3xl md:text-4xl font-hindi font-bold text-wellBeingBlue leading-tight">{q.textHi}</h2>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
          {q.options.map(opt => (
            <button 
              key={opt.id} 
              onClick={() => handleAnswer(opt.indicator)} 
              className="bg-white p-10 text-left group rounded-[3rem] border border-slate-50 hover:border-wellBeingGreen hover:bg-wellBeingGreen/[0.02] transition-all shadow-sm hover:shadow-md"
            >
              <div className="flex items-center space-x-8">
                <div className="w-16 h-16 rounded-full bg-slate-50 flex items-center justify-center font-black text-wellBeingBlue group-hover:bg-wellBeingGreen group-hover:text-white transition-all text-xl">
                  {opt.id.toUpperCase()}
                </div>
                <div className="flex-grow">
                  <p className="font-bold text-xl text-slate-800 mb-2 group-hover:text-wellBeingGreen transition-colors">{opt.en}</p>
                  <p className="text-slate-400 font-hindi font-medium text-lg italic">{opt.hi}</p>
                </div>
              </div>
            </button>
          ))}
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-2xl mx-auto px-6 py-32 text-center">
      <div className="w-24 h-24 bg-wellBeingGreen text-white rounded-full flex items-center justify-center text-4xl mx-auto mb-12 shadow-xl">✓</div>
      <h2 className="text-5xl font-black text-slate-800 uppercase tracking-tighter mb-6">Session Complete</h2>
      <p className="text-slate-500 font-medium mb-16 text-lg">Your well-being check has been completed and stored in our secure database. Our counselors will review the clinical indicators and sync with your institution.</p>
      <button 
        onClick={() => window.location.reload()} 
        className="px-20 py-8 bg-wellBeingBlue text-white rounded-full font-black uppercase tracking-[0.2em] text-[13px] shadow-2xl hover:bg-slate-800 transition-all"
      >
        Return to Portal
      </button>
    </div>
  );
};

export default Quiz;

import React, { useState, useEffect } from 'react';
import { Submission, UserRole, User } from '../types';
import { api } from '../services/api';

interface AdminDashboardProps {
  user: User;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ user }) => {
  const [submissions, setSubmissions] = useState<Submission[]>([]);
  const [filter, setFilter] = useState<'all' | 'CRITICAL'>('all');

  useEffect(() => {
    // Fixed: api.fetchSubmissions is an async function, so we must await it inside a wrapper
    const loadData = async () => {
      const data = await api.fetchSubmissions();
      setSubmissions(data);
    };
    loadData();
  }, []);

  const filteredData = submissions.filter(s => 
    filter === 'all' ? true : s.riskStatus === 'CRITICAL'
  );

  const stats = {
    total: submissions.length,
    critical: submissions.filter(s => s.riskStatus === 'CRITICAL').length,
    moderate: submissions.filter(s => s.riskStatus === 'MODERATE').length,
    stable: submissions.filter(s => s.riskStatus === 'STABLE').length,
  };

  return (
    <div className="max-w-7xl mx-auto px-6 lg:px-8 py-20">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-end mb-16 gap-8">
        <div>
          <h2 className="text-5xl font-black text-slate-800 tracking-tighter uppercase leading-none">
            {user.role === UserRole.ADMIN ? 'MCQ Center' : 'Clinical Portal'}
          </h2>
          <p className="text-slate-400 font-medium mt-3 text-lg italic">Tracking Well-Being for: <span className="text-wellBeingBlue font-black">{user.username}</span></p>
        </div>
        <div className="flex bg-white shadow-sm border border-slate-100 p-2 rounded-full">
          <button 
            onClick={() => setFilter('all')}
            className={`px-8 py-3 rounded-full text-[11px] font-black uppercase tracking-widest transition-all ${filter === 'all' ? 'bg-wellBeingBlue text-white shadow-md' : 'text-slate-400 hover:text-wellBeingBlue'}`}
          >
            All Submissions
          </button>
          <button 
            onClick={() => setFilter('CRITICAL')}
            className={`px-8 py-3 rounded-full text-[11px] font-black uppercase tracking-widest transition-all ${filter === 'CRITICAL' ? 'bg-red-500 text-white shadow-md' : 'text-slate-400 hover:text-red-500'}`}
          >
            Red Flags Only
          </button>
        </div>
      </div>

      {/* Metrics Grid */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-8 mb-16">
        <div className="bg-white p-10 rounded-[3rem] shadow-bento border border-slate-50 group transition-all">
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.3em]">Total Screened</p>
          <p className="text-5xl font-black text-slate-800 mt-3 tracking-tighter">{stats.total}</p>
        </div>
        <div className="bg-emerald-50 p-10 rounded-[3rem] border border-emerald-100/50 group transition-all">
          <p className="text-[10px] font-black text-emerald-600 uppercase tracking-[0.3em]">Healthy</p>
          <p className="text-5xl font-black text-emerald-700 mt-3 tracking-tighter">{stats.stable}</p>
        </div>
        <div className="bg-amber-50 p-10 rounded-[3rem] border border-amber-100/50 group transition-all">
          <p className="text-[10px] font-black text-amber-600 uppercase tracking-[0.3em]">Moderate</p>
          <p className="text-5xl font-black text-amber-700 mt-3 tracking-tighter">{stats.moderate}</p>
        </div>
        <div className="bg-red-50 p-10 rounded-[3rem] border border-red-200 shadow-xl shadow-red-500/10 transition-all">
          <p className="text-[10px] font-black text-red-600 uppercase tracking-[0.3em]">Red Flags</p>
          <p className="text-5xl font-black text-red-700 mt-3 tracking-tighter">{stats.critical}</p>
        </div>
      </div>

      <div className="bg-white rounded-[4rem] overflow-hidden border border-slate-100 shadow-soft-xl">
        <div className="overflow-x-auto">
          <table className="min-w-full divide-y divide-slate-50">
            <thead>
              <tr className="bg-slate-50/50">
                <th className="px-10 py-8 text-left text-[11px] font-black text-slate-400 uppercase tracking-[0.3em]">Student Profile</th>
                <th className="px-10 py-8 text-left text-[11px] font-black text-slate-400 uppercase tracking-[0.3em]">Clinical Status</th>
                <th className="px-10 py-8 text-left text-[11px] font-black text-slate-400 uppercase tracking-[0.3em]">Psychological Conclusion</th>
                <th className="px-10 py-8 text-left text-[11px] font-black text-slate-400 uppercase tracking-[0.3em]">Sync Log</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {filteredData.length === 0 ? (
                <tr>
                  <td colSpan={4} className="px-10 py-32 text-center text-slate-300 font-black uppercase tracking-[0.4em] text-sm">No synchronized records found.</td>
                </tr>
              ) : (
                filteredData.map((s) => (
                  <tr key={s.id} className={`hover:bg-slate-50/30 transition-colors group ${s.riskStatus === 'CRITICAL' ? 'bg-red-50/20' : ''}`}>
                    <td className="px-10 py-10">
                      <div className="text-xl font-black text-slate-800 tracking-tighter group-hover:text-wellBeingBlue transition-colors">{s.student.name}</div>
                      <div className="text-[10px] text-slate-400 font-black uppercase mt-1.5 tracking-widest">Standard {s.student.standard} • {s.student.school}</div>
                    </td>
                    <td className="px-10 py-10">
                      <div className={`inline-flex items-center space-x-3 px-6 py-2.5 rounded-full border ${
                        s.riskStatus === 'CRITICAL' ? 'bg-red-100 text-red-700 border-red-200' : 
                        s.riskStatus === 'MODERATE' ? 'bg-amber-100 text-amber-700 border-amber-200' : 'bg-emerald-100 text-emerald-700 border-emerald-200'
                      }`}>
                        <span className={`w-2.5 h-2.5 rounded-full animate-pulse ${
                          s.riskStatus === 'CRITICAL' ? 'bg-red-600' : 
                          s.riskStatus === 'MODERATE' ? 'bg-amber-600' : 'bg-emerald-600'
                        }`} />
                        <span className="text-[11px] font-black uppercase tracking-widest">{s.riskStatus}</span>
                      </div>
                    </td>
                    <td className="px-10 py-10">
                      <p className={`text-sm leading-relaxed font-medium max-w-md ${s.riskStatus === 'CRITICAL' ? 'text-red-600 font-bold' : 'text-slate-600'}`}>
                        {s.conclusion}
                      </p>
                    </td>
                    <td className="px-10 py-10 text-[11px] text-slate-300 font-black uppercase tracking-tighter">
                      {new Date(s.timestamp).toLocaleDateString()}
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default AdminDashboard;

import React, { useState, useEffect } from 'react';
import { Question, WellBeingLevel, ResponseIndicator } from '../types';
import { api } from '../services/api';

const QuestionManager: React.FC = () => {
  const [questions, setQuestions] = useState<Question[]>([]);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [formData, setFormData] = useState<Partial<Question>>({});

  useEffect(() => {
    // Fixed: api.fetchQuestions is an async function, so we must await it inside a wrapper
    const loadData = async () => {
      const data = await api.fetchQuestions();
      setQuestions(data);
    };
    loadData();
  }, []);

  const handleSave = () => {
    let updated;
    if (editingId === 'new') {
      const newQ: Question = {
        ...formData as Question,
        id: `clinical_${Date.now()}`,
      };
      updated = [...questions, newQ];
    } else {
      updated = questions.map(q => q.id === editingId ? { ...q, ...formData } : q);
    }
    setQuestions(updated);
    api.saveQuestions(updated);
    setEditingId(null);
  };

  const deleteQuestion = (id: string) => {
    if (confirm('Are you sure you want to delete this clinical MCQ?')) {
      const updated = questions.filter(q => q.id !== id);
      setQuestions(updated);
      api.saveQuestions(updated);
    }
  };

  const openEditor = (q?: Question) => {
    if (q) {
      setEditingId(q.id);
      setFormData(q);
    } else {
      setEditingId('new');
      setFormData({
        level: WellBeingLevel.LEVEL_1,
        textEn: '',
        textHi: '',
        options: [
          { id: 'a', en: '', hi: '', indicator: ResponseIndicator.HEALTHY },
          { id: 'b', en: '', hi: '', indicator: ResponseIndicator.HEALTHY },
          { id: 'c', en: '', hi: '', indicator: ResponseIndicator.CONCERN },
          { id: 'd', en: '', hi: '', indicator: ResponseIndicator.RED_FLAG },
        ]
      });
    }
  };

  return (
    <div className="max-w-7xl mx-auto px-6 py-12 animate-fade-in">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-10 gap-4">
        <div>
          <h2 className="text-3xl font-black text-charcoal tracking-tighter uppercase">MCQ Inventory Manager</h2>
          <p className="text-slate-500 font-medium">Bilingual Clinical Assessment Bank</p>
        </div>
        <button 
          onClick={() => openEditor()}
          className="bg-charcoal text-gold px-8 py-3 rounded-2xl font-black uppercase tracking-widest text-xs hover:bg-black transition-all shadow-xl"
        >
          + Add MCQ
        </button>
      </div>

      {editingId && (
        <div className="fixed inset-0 bg-charcoal/80 backdrop-blur-md z-[100] flex items-center justify-center p-4">
          <div className="bg-white rounded-[2.5rem] p-8 md:p-10 max-w-3xl w-full max-h-[90vh] overflow-y-auto shadow-2xl border-4 border-gold">
            <div className="flex justify-between items-center mb-8">
              <h3 className="text-2xl font-black tracking-tighter uppercase">{editingId === 'new' ? 'New Clinical Entry' : 'Update Clinical Entry'}</h3>
              <button onClick={() => setEditingId(null)} className="text-slate-400 hover:text-charcoal font-black">CLOSE</button>
            </div>

            <div className="space-y-6">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div>
                  <label className="block text-[10px] font-black uppercase text-gray-500 tracking-widest mb-2">Target Academic Level</label>
                  <select 
                    value={formData.level}
                    onChange={e => setFormData({...formData, level: e.target.value as WellBeingLevel})}
                    className="w-full p-4 bg-slate-50 border-2 border-slate-100 rounded-2xl font-bold focus:border-gold outline-none transition-all"
                  >
                    {Object.values(WellBeingLevel).map(l => <option key={l} value={l}>{l}</option>)}
                  </select>
                </div>
              </div>

              <div className="grid grid-cols-1 gap-4">
                <div>
                  <label className="block text-[10px] font-black uppercase text-gray-500 tracking-widest mb-2">Question (English)</label>
                  <input 
                    value={formData.textEn}
                    onChange={e => setFormData({...formData, textEn: e.target.value})}
                    className="w-full p-4 bg-slate-50 border-2 border-slate-100 rounded-2xl font-bold focus:border-gold outline-none transition-all"
                  />
                </div>
                <div>
                  <label className="block text-[10px] font-black uppercase text-gray-500 tracking-widest mb-2">Question (Hindi)</label>
                  <input 
                    value={formData.textHi}
                    onChange={e => setFormData({...formData, textHi: e.target.value})}
                    className="w-full p-4 bg-slate-50 border-2 border-slate-100 rounded-2xl font-hindi font-bold focus:border-gold outline-none transition-all"
                  />
                </div>
              </div>

              <div className="space-y-4 pt-4 border-t border-slate-100">
                <p className="text-xs font-black uppercase text-charcoal tracking-widest">Clinical Options & Reasoning</p>
                {formData.options?.map((opt, idx) => (
                  <div key={idx} className="p-6 border-2 border-slate-50 rounded-[2rem] bg-slate-50/50 space-y-4">
                    <div className="flex justify-between items-center">
                      <span className="font-black text-xs uppercase text-slate-400 tracking-tighter">Option {opt.id.toUpperCase()}</span>
                      <select 
                        value={opt.indicator}
                        onChange={e => {
                          const newOpts = [...(formData.options || [])];
                          newOpts[idx].indicator = e.target.value as ResponseIndicator;
                          setFormData({...formData, options: newOpts});
                        }}
                        className={`text-[10px] font-black border-2 rounded-lg px-2 py-1 uppercase tracking-widest transition-colors ${
                          opt.indicator === ResponseIndicator.RED_FLAG ? 'bg-red-50 text-red-600 border-red-100' :
                          opt.indicator === ResponseIndicator.CONCERN ? 'bg-amber-50 text-amber-600 border-amber-100' :
                          'bg-emerald-50 text-emerald-600 border-emerald-100'
                        }`}
                      >
                        {Object.values(ResponseIndicator).map(i => <option key={i} value={i}>{i}</option>)}
                      </select>
                    </div>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                      <input 
                        placeholder="English Response"
                        value={opt.en}
                        onChange={e => {
                          const newOpts = [...(formData.options || [])];
                          newOpts[idx].en = e.target.value;
                          setFormData({...formData, options: newOpts});
                        }}
                        className="w-full p-3 bg-white border border-slate-200 rounded-xl text-sm font-bold"
                      />
                      <input 
                        placeholder="Hindi Response"
                        value={opt.hi}
                        onChange={e => {
                          const newOpts = [...(formData.options || [])];
                          newOpts[idx].hi = e.target.value;
                          setFormData({...formData, options: newOpts});
                        }}
                        className="w-full p-3 bg-white border border-slate-200 rounded-xl text-sm font-hindi font-bold"
                      />
                    </div>
                  </div>
                ))}
              </div>
            </div>

            <div className="flex flex-col sm:flex-row justify-end gap-4 mt-10">
              <button 
                onClick={() => setEditingId(null)} 
                className="px-8 py-4 text-slate-400 font-black uppercase tracking-widest text-[10px]"
              >
                Discard
              </button>
              <button 
                onClick={handleSave} 
                className="px-10 py-4 bg-charcoal text-white rounded-2xl font-black uppercase tracking-widest text-[10px] shadow-2xl hover:bg-black transition-all"
              >
                Commit Changes
              </button>
            </div>
          </div>
        </div>
      )}

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {questions.map(q => (
          <div key={q.id} className="bg-white border-2 border-slate-50 rounded-[2.5rem] p-8 hover:border-gold transition-all duration-300 group flex flex-col justify-between">
            <div>
              <div className="flex items-center space-x-3 mb-4">
                <span className="text-[10px] font-black bg-gold text-charcoal px-3 py-1 rounded-full uppercase tracking-widest">{q.level}</span>
                <span className="text-[10px] font-bold text-slate-300 uppercase tracking-[0.2em]">{q.id}</span>
              </div>
              <h4 className="font-black text-xl text-charcoal leading-tight mb-2">{q.textEn}</h4>
              <p className="text-md text-slate-400 font-hindi font-medium italic">{q.textHi}</p>
            </div>
            <div className="flex justify-end space-x-3 mt-8 pt-6 border-t border-slate-50">
              <button onClick={() => openEditor(q)} className="px-4 py-2 text-[10px] font-black text-charcoal uppercase tracking-widest hover:text-gold transition-colors">Edit</button>
              <button onClick={() => deleteQuestion(q.id)} className="px-4 py-2 text-[10px] font-black text-red-400 uppercase tracking-widest hover:text-red-600 transition-colors">Delete</button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default QuestionManager;

