                <div className="flex-grow">
                  <p className="font-bold text-xl text-slate-800 mb-2 group-hover:text-wellBeingGreen transition-colors">{opt.en}</p>
                  <p className="text-slate-400 font-hindi font-medium text-lg italic">{opt.hi}</p>
                </div>
              </div>
            </button>
          ))}
        </div>
      </div>
    );
  }

  if (step === 'completed' && finalSubmission) {
    return (
      <div className="max-w-5xl mx-auto px-6 py-20 animate-fade-in">
        <div className="text-center mb-16">
          <motion.div 
            initial={{ scale: 0 }}
            animate={{ scale: 1 }}
            className="w-24 h-24 bg-wellBeingGreen text-white rounded-full flex items-center justify-center text-5xl mx-auto mb-8 shadow-xl"
          >
            ✓
          </motion.div>
          <h2 className="text-5xl font-black text-charcoal uppercase tracking-tighter mb-4">Thank You!<br/>Assessment Submitted</h2>
          <p className="text-slate-500 font-bold uppercase tracking-widest text-xs">Clinical markers have been synchronized with the NitGyanam Portal</p>
        </div>

        {/* AI Counselor Report Section */}
        <div className="bg-white p-8 md:p-16 rounded-[4rem] shadow-soft-xl border border-slate-100 mb-12">
          <div className="flex items-center space-x-4 mb-10 border-b border-slate-50 pb-8">
            <div className="w-12 h-12 bg-wellBeingBlue text-white rounded-2xl flex items-center justify-center font-black text-xl">AI</div>
            <div>
              <h3 className="text-2xl font-black text-slate-800 tracking-tighter uppercase">Counselor Behavioral Analysis</h3>
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">3-Step Psychological Report</p>
            </div>
          </div>

          <div className="prose prose-slate max-w-none">
            <div className="whitespace-pre-wrap font-medium text-slate-700 leading-relaxed text-lg">
              {finalSubmission.aiReport}
            </div>
          </div>
        </div>

        {/* Results Summary Table Card */}
        <div className="bg-white p-8 md:p-12 rounded-[4rem] shadow-bento border border-slate-50 overflow-hidden">
          <h3 className="text-xl font-black text-slate-800 uppercase tracking-tight mb-8 px-4">Response Overview</h3>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="bg-slate-50">
                  <th className="px-6 py-5 text-[10px] font-black uppercase text-slate-400 tracking-widest">Question</th>
                  <th className="px-6 py-5 text-[10px] font-black uppercase text-slate-400 tracking-widest">Your Answer</th>
                  <th className="px-6 py-5 text-[10px] font-black uppercase text-slate-400 tracking-widest text-right">Clinical Goal</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {questions.filter(q => finalSubmission.answers[q.id]).map(q => {
                  const indicator = finalSubmission.answers[q.id];
                  const isHealthy = indicator === ResponseIndicator.HEALTHY;
                  const isCritical = indicator === ResponseIndicator.RED_FLAG;

                  return (
                    <tr key={q.id} className="hover:bg-slate-50/50 transition-colors">
                      <td className="px-6 py-8">
                        <p className="font-bold text-slate-800 text-sm leading-snug">{q.textEn}</p>
                        <p className="text-[10px] text-slate-400 font-hindi mt-1 italic">{q.textHi}</p>
                      </td>
                      <td className="px-6 py-8">
                        <span className={`px-4 py-2 rounded-full text-[10px] font-black uppercase tracking-widest border ${
                          isHealthy ? 'bg-emerald-50 text-emerald-600 border-emerald-100' :
                          isCritical ? 'bg-red-50 text-red-600 border-red-100' :
                          'bg-amber-50 text-amber-600 border-amber-100'
                        }`}>
                          {indicator}
                        </span>
                      </td>
                      <td className="px-6 py-8 text-right">
                        <span className="text-[10px] font-black uppercase text-wellBeingGreen tracking-widest bg-emerald-50/50 px-3 py-1.5 rounded-lg border border-emerald-50">Optimal Wellness</span>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>

        <div className="mt-16 text-center">
          <button 
            onClick={() => window.location.reload()} 
            className="px-20 py-8 bg-charcoal text-white rounded-full font-black uppercase tracking-[0.2em] text-[13px] shadow-2xl hover:bg-wellBeingBlue transition-all transform hover:scale-105 active:scale-95"
          >
            Back to Home
          </button>
        </div>
      </div>
    );
  }

  return null;
};

export default Quiz;

