                <div className="pt-10 border-t border-slate-100 flex justify-end">
                   <button 
                    onClick={() => setSelectedSubmission(null)}
                    className="bg-charcoal text-white px-12 py-5 rounded-full text-[11px] font-black uppercase tracking-widest hover:bg-wellBeingBlue transition-all shadow-xl"
