                  <div>
                    <p className="text-[9px] font-black uppercase text-slate-400 tracking-widest mb-1">Diagnostic ID</p>
                    <p className="font-bold text-wellBeingBlue">{selectedSubmission.id}</p>
                  </div>
                  <div>
                    <p className="text-[9px] font-black uppercase text-slate-400 tracking-widest mb-1">Classification</p>
                    <p className={`font-black uppercase text-[10px] ${
                      selectedSubmission.riskStatus === 'CRITICAL' ? 'text-red-500' : 
                      selectedSubmission.riskStatus === 'MODERATE' ? 'text-amber-500' : 'text-emerald-500'
                    }`}>{selectedSubmission.riskStatus}</p>
                  </div>
                </div>

                <div className="prose prose-slate prose-lg max-w-none">
                  <div className="whitespace-pre-wrap font-medium text-slate-700 leading-relaxed text-lg border-l-4 border-slate-100 pl-8">
                    {selectedSubmission.aiReport || "Report generation in progress..."}
                  </div>
                </div>
              </div>

              <div className="px-12 py-8 bg-slate-50 border-t border-slate-100 flex justify-between items-center shrink-0">
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">
                  © NitGyanam Clinical Services
                </p>
                <div className="flex gap-4">
                  <button 
                    onClick={() => window.print()}
                    className="px-6 py-3 border-2 border-slate-200 rounded-xl text-[10px] font-black uppercase tracking-widest text-slate-600 hover:border-charcoal transition-all"
                  >
                    Save as PDF
                  </button>
                  <button 
                    onClick={() => setSelectedSubmission(null)}
                    className="bg-charcoal text-white px-10 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-wellBeingBlue transition-all"
                  >
                    Done
                  </button>
                </div>
              </div>
            </motion.div>
          </>
        )}
      </AnimatePresence>
    </div>
  );
};

