export enum WellBeingLevel {
  LEVEL_1 = 'Std 1 to 3',
  LEVEL_2 = 'Std 4 to 6',
  LEVEL_3 = 'Std 7 to 8',
  LEVEL_4 = 'Std 9 to 10',
}

export enum ResponseIndicator {
  HEALTHY = 'Healthy/Positive',
  CONCERN = 'Moderate Concern',
  RED_FLAG = 'Critical Red Flag',
}

export enum UserRole {
  ADMIN = 'ADMIN',
  TEACHER = 'TEACHER',
  STUDENT = 'STUDENT'
}

export interface User {
  username: string;
  role: UserRole;
}

export interface Option {
  id: string;
  en: string;
  hi: string;
  indicator: ResponseIndicator;
}

export interface Question {
  id: string;
  level: WellBeingLevel;
  textEn: string;
  textHi: string;
  options: Option[];
}

export interface StudentInfo {
  name: string;
  age: string;
  standard: string;
  school: string;
}

export interface Submission {
  id: string;
  student: StudentInfo;
  level: WellBeingLevel;
  answers: { [questionId: string]: { indicator: ResponseIndicator; optionId: string } };
  metrics: {
    healthyCount: number;
    concernCount: number;
    redFlagCount: number;
    totalQuestions: number;
  };
  conclusion: string;
  aiReport?: string; // AI generated psychological report
  riskStatus: 'STABLE' | 'MODERATE' | 'CRITICAL';
  timestamp: number;
}

import { Question, Submission, ResponseIndicator, WellBeingLevel } from '../types';
import { QUIZ_DATA } from '../constants';
import { GoogleGenAI } from "@google/genai";

const QUESTIONS_KEY = 'nit_gyanam_questions_v2';
const SUBMISSIONS_KEY = 'nit_gyanam_submissions_v2';

export const api = {
  fetchQuestions: async (): Promise<Question[]> => {
    const saved = localStorage.getItem(QUESTIONS_KEY);
    if (!saved) {
      localStorage.setItem(QUESTIONS_KEY, JSON.stringify(QUIZ_DATA));
      return QUIZ_DATA;
    }
    return JSON.parse(saved);
  },

  saveQuestions: async (questions: Question[]) => {
    localStorage.setItem(QUESTIONS_KEY, JSON.stringify(questions));
  },

  submitAssessment: async (submission: Submission) => {
    const saved = localStorage.getItem(SUBMISSIONS_KEY);
    const submissions: Submission[] = saved ? JSON.parse(saved) : [];
    submissions.unshift(submission);
    localStorage.setItem(SUBMISSIONS_KEY, JSON.stringify(submissions));
    return submission;
  },

  fetchSubmissions: async (): Promise<Submission[]> => {
    const saved = localStorage.getItem(SUBMISSIONS_KEY);
    return saved ? JSON.parse(saved) : [];
  },

  generateAIAnalysis: async (submission: Submission, questions: Question[]): Promise<string> => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    const answerSummary = Object.entries(submission.answers).map(([qid, ans]) => {
      const q = questions.find(q => q.id === qid);
      const opt = q?.options.find(o => o.id === ans.optionId);
      return `- **${q?.textEn}**: Selected "${opt?.en}" (Status: ${ans.indicator})`;
    }).join('\n');

    const prompt = `Student Assessment Data:\n${answerSummary}\n\nStudent Profile: ${submission.student.name}, Age ${submission.student.age}, Grade ${submission.student.standard}`;

    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: {
          systemInstruction: `Role: You are a Senior Clinical Child Psychologist and Behavioral Analyst.
Task: Provide a professional diagnostic report based on student screening data.
Tone: Clinical, objective, and supportive. Use professional medical and psychological terminology.
Output format: You must generate a report strictly in the following 3 sections using clear headers:

### SECTION 1: BEHAVIORAL SYNTHESIS
Provide a deep-dive analysis of the student's current psychological and behavioral patterns based on the data. Identify specific triggers or strengths (e.g., social withdrawal, academic anxiety, high resiliency, or sleep disturbances).

### SECTION 2: DIAGNOSTIC CLASSIFICATION
Categorize the student's status into exactly one:
- **STABLE (Standard Wellbeing)**: High healthy indicators, minor normal stress.
- **MODERATE (Monitoring Recommended)**: Emerging patterns of anxiety, social isolation, or performance pressure.
- **CRITICAL (Immediate Intervention)**: High-risk markers for severe anxiety, clinical depression, or significant behavioral deviation.

### SECTION 3: INTERVENTION STRATEGY
Provide professional, actionable recommendations:
- **For Educators**: Classroom adjustments, social integration tactics.
- **For Parents**: Home environment adjustments, communication strategies.
- **For Counselors**: Specific areas for therapy or coaching.

Include a "Professional Disclaimer" at the end stating that this is an AI-assisted screening tool and should be validated by a licensed professional.`,
        }
      });
      return response.text || "Report unavailable.";
    } catch (error) {
      console.error("AI Analysis Error:", error);
      return "Psychological analysis could not be completed at this time.";
    }
  },

  analyzeResults: (answers: ResponseIndicator[]) => {
    const total = answers.length;
    const redFlagCount = answers.filter(a => a === ResponseIndicator.RED_FLAG).length;
    const concernCount = answers.filter(a => a === ResponseIndicator.CONCERN).length;
    const healthyCount = answers.filter(a => a === ResponseIndicator.HEALTHY).length;

    const redFlagPct = (redFlagCount / total) * 100;

    if (redFlagPct >= 10) {
      return {
        riskStatus: 'CRITICAL' as const,
        conclusion: 'URGENT INTERVENTION REQUIRED. High-risk psychological markers detected.'
      };
    } else if (concernCount > healthyCount || concernCount > (total * 0.3)) {
      return {
        riskStatus: 'MODERATE' as const,
        conclusion: 'MODERATE STRESS DETECTED. Patterns of anxiety or emotional fatigue identified.'
      };
    } else {
      return {
        riskStatus: 'STABLE' as const,
        conclusion: 'STUDENT APPEARS STABLE. Healthy adjustment markers noted.'
      };
    }
  }
};

import React, { useState, useMemo, useEffect } from 'react';
import { WellBeingLevel, Question, ResponseIndicator, StudentInfo, Submission, Option } from '../types';
import { api } from '../services/api';
import { motion, AnimatePresence } from 'framer-motion';

interface QuizProps {
  onComplete: (submission: Submission) => void;
}

type QuizStep = 'level-select' | 'student-info' | 'questions' | 'completed' | 'syncing';

const Quiz: React.FC<QuizProps> = ({ onComplete }) => {
  const [step, setStep] = useState<QuizStep>('level-select');
  const [questions, setQuestions] = useState<Question[]>([]);
  const [selectedLevel, setSelectedLevel] = useState<WellBeingLevel | null>(null);
  const [studentInfo, setStudentInfo] = useState<StudentInfo>({ name: '', age: '', standard: '', school: '' });
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [answers, setAnswers] = useState<{ [id: string]: { indicator: ResponseIndicator; optionId: string } }>({});
  const [tempOption, setTempOption] = useState<Option | null>(null);
  const [finalSubmission, setFinalSubmission] = useState<Submission | null>(null);

  useEffect(() => {
    const load = async () => {
      const qData = await api.fetchQuestions();
      setQuestions(qData);
    };
    load();
  }, []);

  const filteredQuestions = useMemo(() => {
    return questions.filter(q => q.level === selectedLevel);
  }, [selectedLevel, questions]);

  const progress = filteredQuestions.length > 0 
    ? Math.round(((currentQuestionIndex) / filteredQuestions.length) * 100) 
    : 0;

  const handleNext = async () => {
    if (!tempOption) return;

    const questionId = filteredQuestions[currentQuestionIndex].id;
    const newAnswers = { 
      ...answers, 
      [questionId]: { indicator: tempOption.indicator, optionId: tempOption.id } 
    };
    setAnswers(newAnswers);
    setTempOption(null);

    if (currentQuestionIndex < filteredQuestions.length - 1) {
      setCurrentQuestionIndex(prev => prev + 1);
    } else {
      setStep('syncing');
      const answerList = Object.values(newAnswers).map(a => a.indicator);
      const { riskStatus, conclusion } = api.analyzeResults(answerList);

      const submission: Submission = {
        id: `sub_${Math.random().toString(36).substr(2, 9)}`,
        student: studentInfo,
        level: selectedLevel!,
        answers: newAnswers,
        metrics: {
          healthyCount: answerList.filter(v => v === ResponseIndicator.HEALTHY).length,
          concernCount: answerList.filter(v => v === ResponseIndicator.CONCERN).length,
          redFlagCount: answerList.filter(v => v === ResponseIndicator.RED_FLAG).length,
          totalQuestions: answerList.length
        },
        riskStatus,
        conclusion,
        timestamp: Date.now(),
      };

      const aiAnalysis = await api.generateAIAnalysis(submission, questions);
      submission.aiReport = aiAnalysis;

      await api.submitAssessment(submission);
      setFinalSubmission(submission);
      onComplete(submission);
      setStep('completed');
    }
  };

  if (step === 'syncing') {
    return (
      <div className="max-w-2xl mx-auto px-6 py-40 text-center">
        <div className="w-20 h-20 border-4 border-wellBeingBlue border-t-transparent rounded-full animate-spin mx-auto mb-10"></div>
        <h2 className="text-3xl font-black text-slate-800 uppercase tracking-tighter mb-4">Generating Clinical Report</h2>
        <p className="text-slate-400 font-bold uppercase tracking-[0.3em] text-[10px]">AI Counselor is synthesizing your behavioral markers...</p>
      </div>
    );
  }

  if (step === 'level-select') {
    return (
      <div className="max-w-5xl mx-auto px-6 py-24">
        <div className="text-center mb-16">
          <h2 className="text-4xl md:text-5xl font-black text-wellBeingBlue tracking-tighter uppercase mb-6">Select Your Grade</h2>
          <p className="text-slate-400 font-bold uppercase tracking-widest text-xs">Choose the tier that fits your standard</p>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
          {Object.values(WellBeingLevel).map((level) => (
            <button
              key={level}
              onClick={() => { setSelectedLevel(level); setStep('student-info'); }}
              className="bg-white p-12 text-left group border border-slate-100 rounded-[3rem] hover:border-wellBeingBlue transition-all shadow-bento hover:shadow-xl"
            >
              <div className="flex items-center justify-between">
                <div>
                  <h3 className="text-3xl font-black text-slate-800 group-hover:text-wellBeingBlue transition-colors tracking-tighter">{level}</h3>
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mt-3">Interactive Self-Check</p>
                </div>
                <div className="w-16 h-16 rounded-full bg-slate-50 flex items-center justify-center text-slate-300 group-hover:bg-wellBeingBlue group-hover:text-white transition-all">
                  <span className="text-3xl font-bold">→</span>
                </div>
              </div>
            </button>
          ))}
        </div>
      </div>
    );
  }

  if (step === 'student-info') {
    return (
      <div className="max-w-2xl mx-auto px-6 py-24">
        <div className="bg-white p-12 shadow-soft-xl rounded-[3rem] border border-slate-100">
          <h2 className="text-3xl font-black text-slate-800 tracking-tighter uppercase mb-10 text-center">Student Details</h2>
          <form onSubmit={e => { e.preventDefault(); setStep('questions'); }} className="space-y-8">
            <div className="space-y-3">
               <label className="text-[10px] font-black uppercase text-gray-400 tracking-widest px-1">Full Name</label>
               <input required placeholder="Student Name" className="w-full px-8 py-5 rounded-[2rem] bg-slate-50 border border-transparent focus:bg-white focus:border-wellBeingBlue outline-none font-bold text-slate-800 transition-all" onChange={e => setStudentInfo({...studentInfo, name: e.target.value})} />
            </div>
            <div className="grid grid-cols-2 gap-8">
               <div className="space-y-3">
                  <label className="text-[10px] font-black uppercase text-gray-400 tracking-widest px-1">Standard</label>
                  <input required placeholder="Class" className="w-full px-8 py-5 rounded-[2rem] bg-slate-50 border border-transparent focus:bg-white focus:border-wellBeingBlue outline-none font-bold text-slate-800 transition-all" onChange={e => setStudentInfo({...studentInfo, standard: e.target.value})} />
               </div>
               <div className="space-y-3">
                  <label className="text-[10px] font-black uppercase text-gray-400 tracking-widest px-1">Age</label>
                  <input required type="number" placeholder="Age" className="w-full px-8 py-5 rounded-[2rem] bg-slate-50 border border-transparent focus:bg-white focus:border-wellBeingBlue outline-none font-bold text-slate-800 transition-all" onChange={e => setStudentInfo({...studentInfo, age: e.target.value})} />
               </div>
            </div>
            <div className="space-y-3">
               <label className="text-[10px] font-black uppercase text-gray-400 tracking-widest px-1">School Name</label>
               <input required placeholder="Enter School" className="w-full px-8 py-5 rounded-[2rem] bg-slate-50 border border-transparent focus:bg-white focus:border-wellBeingBlue outline-none font-bold text-slate-800 transition-all" onChange={e => setStudentInfo({...studentInfo, school: e.target.value})} />
            </div>
            <button type="submit" className="w-full mt-6 bg-wellBeingBlue text-white font-black py-6 rounded-full shadow-lg hover:shadow-wellBeingBlue/20 transition-all uppercase tracking-[0.2em] text-[11px]">Begin Diagnostic</button>
          </form>
        </div>
      </div>
    );
  }

  if (step === 'questions') {
    const q = filteredQuestions[currentQuestionIndex];
    if (!q) return <div className="p-32 text-center font-black text-wellBeingBlue animate-pulse">Initializing Assessment...</div>;

    return (
      <div className="max-w-6xl mx-auto px-6 py-20">
        <div className="mb-16 flex flex-col md:flex-row items-center justify-between gap-8">
          <div className="flex items-center space-x-6">
            <span className="text-[11px] font-black text-white bg-wellBeingBlue uppercase tracking-[0.2em] px-6 py-2.5 rounded-full shadow-sm">{selectedLevel}</span>
            <span className="text-xs font-bold text-slate-400 uppercase tracking-[0.3em]">Module {currentQuestionIndex + 1} / {filteredQuestions.length}</span>
          </div>
          <div className="w-full md:w-80 bg-slate-200 rounded-full h-3 overflow-hidden">
            <div className="bg-wellBeingGreen h-full transition-all duration-700" style={{ width: `${progress}%` }}></div>
          </div>
        </div>

        <div className="bg-white p-12 md:p-16 rounded-[4rem] border border-slate-100 shadow-bento mb-16 text-center">
             <h2 className="text-3xl md:text-4xl font-black text-slate-800 leading-tight tracking-tighter mb-8">{q.textEn}</h2>
             <div className="w-20 h-1 bg-wellBeingGreen/20 mx-auto mb-8"></div>
             <h2 className="text-3xl md:text-4xl font-hindi font-bold text-wellBeingBlue leading-tight">{q.textHi}</h2>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-8 mb-16">
          {q.options.map(opt => (
            <button 
              key={opt.id} 
              onClick={() => setTempOption(opt)} 
              className={`bg-white p-10 text-left group rounded-[3rem] border transition-all shadow-sm hover:shadow-md ${tempOption?.id === opt.id ? 'border-wellBeingBlue bg-wellBeingBlue/[0.03]' : 'border-slate-50 hover:border-wellBeingGreen'}`}
            >
              <div className="flex items-center space-x-8">
                <div className={`w-16 h-16 rounded-full flex items-center justify-center font-black transition-all text-xl ${tempOption?.id === opt.id ? 'bg-wellBeingBlue text-white' : 'bg-slate-50 text-wellBeingBlue group-hover:bg-wellBeingGreen group-hover:text-white'}`}>
                  {opt.id.toUpperCase()}
                </div>
                <div className="flex-grow">
                  <p className={`font-bold text-xl mb-2 transition-colors ${tempOption?.id === opt.id ? 'text-wellBeingBlue' : 'text-slate-800 group-hover:text-wellBeingGreen'}`}>{opt.en}</p>
                  <p className="text-slate-400 font-hindi font-medium text-lg italic">{opt.hi}</p>
                </div>
              </div>
            </button>
          ))}
        </div>

        <div className="flex justify-center">
          <button 
            disabled={!tempOption}
            onClick={handleNext}
            className={`px-24 py-7 rounded-full font-black uppercase tracking-[0.2em] text-[11px] transition-all shadow-xl ${tempOption ? 'bg-charcoal text-white hover:bg-black scale-100' : 'bg-slate-100 text-slate-300 scale-95 cursor-not-allowed'}`}
          >
            {currentQuestionIndex === filteredQuestions.length - 1 ? 'Finish Assessment' : 'Next Question'}
          </button>
        </div>
      </div>
    );
  }

  if (step === 'completed' && finalSubmission) {
    return (
      <div className="max-w-7xl mx-auto px-6 py-20 animate-fade-in">
        <div className="text-center mb-16">
          <div className="w-24 h-24 bg-wellBeingGreen text-white rounded-full flex items-center justify-center text-4xl mx-auto mb-10 shadow-xl">✓</div>
          <h2 className="text-4xl md:text-6xl font-black text-slate-800 uppercase tracking-tighter mb-4">Assessment Complete</h2>
          <p className="text-slate-500 font-bold uppercase tracking-widest text-xs mb-4">Diagnostic ID: {finalSubmission.id}</p>
          <h3 className="text-2xl font-black text-wellBeingBlue uppercase tracking-tighter">Thank you for sharing, {studentInfo.name}!</h3>
        </div>

        <div className="flex flex-col space-y-12">
          {/* Professional Clinical Report Document */}
          <div className="bg-white rounded-[4rem] shadow-soft-xl border border-slate-100 overflow-hidden">
             <div className="bg-slate-900 px-12 py-12 text-white flex flex-col md:flex-row justify-between items-center gap-6">
                <div>
                  <h3 className="text-2xl font-black uppercase tracking-tighter">Clinical Counselor Report</h3>
                  <p className="text-wellBeingBlue text-[10px] font-black uppercase tracking-[0.3em] mt-2">NitGyanam Well-Being Architecture</p>
                </div>
                <div className="text-center md:text-right">
                  <p className="text-[10px] font-black uppercase tracking-widest text-white/40">Student Profile</p>
                  <p className="text-gold font-bold">{finalSubmission.student.name} | {finalSubmission.student.standard}</p>
                </div>
             </div>

             <div className="p-12 md:p-16">
                <div className="prose prose-slate prose-lg max-w-none mb-16">
                  <div className="whitespace-pre-wrap font-medium text-slate-700 leading-relaxed border-l-4 border-gold/30 pl-8">
