                              </td>
                              <td className="px-8 py-8 text-right">
                                <div className={`w-3 h-3 rounded-full ml-auto ${
                                  isHealthy ? 'bg-wellBeingGreen' :
                                  isRed ? 'bg-red-500' : 'bg-amber-500'
                                } shadow-sm`} />
                              </td>
                            </tr>
                          );
                        })}
                      </tbody>
                    </table>
                  </div>
                </div>
             </div>

             <div className="bg-slate-50 px-12 py-8 text-center border-t border-slate-100">
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">
                  End of Certified Behavioral Diagnostic Report ID: {finalSubmission.id}
                </p>
             </div>
          </div>

          <div className="flex justify-center pt-8">
            <button 
              onClick={() => window.location.reload()} 
              className="px-24 py-8 bg-charcoal text-white rounded-full font-black uppercase tracking-[0.2em] text-[13px] shadow-2xl hover:bg-wellBeingBlue transition-all transform hover:scale-105"
            >
              Finish and Close Portal
            </button>
          </div>
        </div>
      </div>
    );
  }

  return null;
};

