        </div>

        <div className="bg-white rounded-[2rem] shadow-[0_10px_40px_rgba(0,0,0,0.03)] border border-blue-50/50 p-8 md:p-14">
          <div className="space-y-12">
            {filteredQuestions.map((q, idx) => {
              const ansData = finalSubmission.answers[q.id];
              const selectedOption = q.options.find(o => o.id === ansData?.optionId);

              return (
