import { createClient } from '@supabase/supabase-js';

// Configuration for Supabase - These should eventually be moved to process.env
// For now, these act as placeholders for the user to connect their project.
const SUPABASE_URL = process.env.SUPABASE_URL || '';
const SUPABASE_ANON_KEY = process.env.SUPABASE_ANON_KEY || '';

export const supabase = (SUPABASE_URL && SUPABASE_ANON_KEY) 
  ? createClient(SUPABASE_URL, SUPABASE_ANON_KEY)
  : null;

import { Question, Submission, ResponseIndicator, WellBeingLevel } from '../types';
import { QUIZ_DATA } from '../constants';
import { GoogleGenAI } from "@google/genai";
import { supabase } from './supabase';

const QUESTIONS_KEY = 'nit_gyanam_questions_v2';
const SUBMISSIONS_KEY = 'nit_gyanam_submissions_v2';

export const api = {
  fetchQuestions: async (): Promise<Question[]> => {
    // 1. Try cloud
    if (supabase) {
      const { data, error } = await supabase.from('questions').select('*');
      if (!error && data && data.length > 0) return data;
    }

    // 2. Fallback to Local
    const saved = localStorage.getItem(QUESTIONS_KEY);
    if (!saved) {
      localStorage.setItem(QUESTIONS_KEY, JSON.stringify(QUIZ_DATA));
      return QUIZ_DATA;
    }
    return JSON.parse(saved);
  },

  saveQuestions: async (questions: Question[]) => {
    // 1. Save to Cloud
    if (supabase) {
      await supabase.from('questions').upsert(questions);
    }
    // 2. Always backup to Local
    localStorage.setItem(QUESTIONS_KEY, JSON.stringify(questions));
  },

  submitAssessment: async (submission: Submission) => {
    // 1. Submit to Cloud
    if (supabase) {
      try {
        const dbSubmission = {
          id: submission.id,
          student_name: submission.student.name,
          student_age: submission.student.age,
          student_standard: submission.student.standard,
          student_school: submission.student.school,
          level: submission.level,
          answers: submission.answers,
          risk_status: submission.riskStatus,
          conclusion: submission.conclusion,
          ai_report: submission.aiReport,
          timestamp: submission.timestamp
        };
        const { error } = await supabase.from('submissions').insert([dbSubmission]);
        if (error) console.warn("Supabase Sync Failed:", error);
      } catch (e) {
        console.error("Cloud DB Error:", e);
      }
    }

    // 2. Local Persistence (Ensures app works offline/without DB)
    const saved = localStorage.getItem(SUBMISSIONS_KEY);
    const submissions: Submission[] = saved ? JSON.parse(saved) : [];
    submissions.unshift(submission);
    localStorage.setItem(SUBMISSIONS_KEY, JSON.stringify(submissions));

    return submission;
  },

  fetchSubmissions: async (): Promise<Submission[]> => {
    // 1. Fetch from Cloud
    if (supabase) {
      const { data, error } = await supabase
        .from('submissions')
        .select('*')
        .order('timestamp', { ascending: false });

      if (!error && data) {
        // Map back to our frontend interface
        return data.map(d => ({
          id: d.id,
          student: {
            name: d.student_name,
            age: d.student_age,
            standard: d.student_standard,
            school: d.student_school
          },
          level: d.level,
          answers: d.answers,
          riskStatus: d.risk_status,
          conclusion: d.conclusion,
          aiReport: d.ai_report,
          timestamp: d.timestamp,
          metrics: {
            totalQuestions: Object.keys(d.answers).length,
            healthyCount: 0, concernCount: 0, redFlagCount: 0 // Calculations done on-the-fly or simplified
          }
        }));
      }
    }

    // 2. Fallback to Local
    const saved = localStorage.getItem(SUBMISSIONS_KEY);
    return saved ? JSON.parse(saved) : [];
  },

  generateAIAnalysis: async (submission: Submission, questions: Question[]): Promise<string> => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    const answerSummary = Object.entries(submission.answers).map(([qid, ans]: [string, any]) => {
      const q = questions.find(q => q.id === qid);
      const opt = q?.options.find(o => o.id === ans.optionId);
      return `- **${q?.textEn}**: Selected "${opt?.en}" (Status: ${ans.indicator})`;
    }).join('\n');

    const prompt = `Student Assessment Data:\n${answerSummary}\n\nStudent Profile: ${submission.student.name}, Age ${submission.student.age}, Grade ${submission.student.standard}`;

    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: {
          systemInstruction: `Role: Senior Clinical Child Psychologist. Provide a diagnostic report with 3 sections: Behavioral Synthesis, Diagnostic Classification (STABLE/MODERATE/CRITICAL), and Intervention Strategy. Use professional terminology. Include disclaimer at end.`,
        }
      });
      return response.text || "Report unavailable.";
    } catch (error) {
      console.error("AI Analysis Error:", error);
      return "Psychological analysis could not be completed at this time.";
    }
  },

  analyzeResults: (answers: ResponseIndicator[]) => {
    const total = answers.length;
    const redFlagCount = answers.filter(a => a === ResponseIndicator.RED_FLAG).length;
    const concernCount = answers.filter(a => a === ResponseIndicator.CONCERN).length;
    const healthyCount = answers.filter(a => a === ResponseIndicator.HEALTHY).length;

    const redFlagPct = (redFlagCount / total) * 100;

    if (redFlagPct >= 10) {
      return {
        riskStatus: 'CRITICAL' as const,
        conclusion: 'URGENT INTERVENTION REQUIRED. High-risk psychological markers detected.'
      };
    } else if (concernCount > healthyCount || concernCount > (total * 0.3)) {
      return {
        riskStatus: 'MODERATE' as const,
        conclusion: 'MODERATE STRESS DETECTED. Patterns of anxiety or emotional fatigue identified.'
      };
    } else {
      return {
        riskStatus: 'STABLE' as const,
        conclusion: 'STUDENT APPEARS STABLE. Healthy adjustment markers noted.'
      };
    }
  }
};

