    setUser(null);
    localStorage.removeItem('ng_user_session');
    setActiveView('home');
  };

  const handleLogoClick = () => {
    const newCount = logoClicks + 1;
    setLogoClicks(newCount);
    if (newCount === 5) {
      setShowDebug(true);
      setLogoClicks(0);
