                    <span className="text-3xl font-bold">→</span>
                  </div>
                </button>
              ))}
            </div>
          </motion.div>
        )}

        {step === 'student-info' && (
          <motion.div 
            key="student-info"
            initial={{ opacity: 0, scale: 0.95 }}
            animate={{ opacity: 1, scale: 1 }}
