              <div className="absolute top-0 right-0 w-24 h-24 bg-wellBeingBlue/5 rounded-bl-[4rem]" />
              <div className="text-center mb-16">
                <span className="text-wellBeingBlue text-[10px] font-black uppercase tracking-[0.5em] block mb-4">Step 02</span>
                <h2 className="text-4xl font-black text-slate-900 tracking-tighter uppercase mb-2 leading-none">Student Profile</h2>
