import React, { useState, useMemo, useEffect } from 'react';
import { WellBeingLevel, Question, ResponseIndicator, StudentInfo, Submission, Option } from '../types';
import { api } from '../services/api';
import { motion, AnimatePresence } from 'framer-motion';

interface QuizProps {
  onComplete: (submission: Submission) => void;
}

type QuizStep = 'level-select' | 'student-info' | 'questions' | 'completed' | 'syncing';

const Quiz: React.FC<QuizProps> = ({ onComplete }) => {
  const [step, setStep] = useState<QuizStep>('level-select');
  const [questions, setQuestions] = useState<Question[]>([]);
  const [selectedLevel, setSelectedLevel] = useState<WellBeingLevel | null>(null);
  const [studentInfo, setStudentInfo] = useState<StudentInfo>({ name: '', age: '', standard: '', school: '' });
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [answers, setAnswers] = useState<{ [id: string]: { indicator: ResponseIndicator; optionId: string } }>({});
  const [tempOption, setTempOption] = useState<Option | null>(null);

  useEffect(() => {
    const load = async () => {
      const qData = await api.fetchQuestions();
      setQuestions(qData);
    };
    load();
  }, []);

  const filteredQuestions = useMemo(() => {
    return questions.filter(q => q.level === selectedLevel);
  }, [selectedLevel, questions]);

  const progress = filteredQuestions.length > 0 
    ? Math.round(((currentQuestionIndex) / filteredQuestions.length) * 100) 
    : 0;

  const handleNext = async () => {
    if (!tempOption) return;
    const questionId = filteredQuestions[currentQuestionIndex].id;
    const newAnswers = { ...answers, [questionId]: { indicator: tempOption.indicator, optionId: tempOption.id } };
    setAnswers(newAnswers);
    setTempOption(null);

    if (currentQuestionIndex < filteredQuestions.length - 1) {
      setCurrentQuestionIndex(prev => prev + 1);
    } else {
      setStep('syncing');
      const answerList = Object.values(newAnswers).map(a => a.indicator);
      const { riskStatus, conclusion } = api.analyzeResults(answerList);

      const submission: Submission = {
        id: `CLN-${Math.random().toString(36).substr(2, 6).toUpperCase()}`,
        student: studentInfo,
        level: selectedLevel!,
        answers: newAnswers,
        metrics: {
          healthyCount: answerList.filter(v => v === ResponseIndicator.HEALTHY).length,
          concernCount: answerList.filter(v => v === ResponseIndicator.CONCERN).length,
          redFlagCount: answerList.filter(v => v === ResponseIndicator.RED_FLAG).length,
          totalQuestions: answerList.length
        },
        riskStatus,
        conclusion,
        timestamp: Date.now(),
      };

      const aiAnalysis = await api.generateAIAnalysis(submission, questions);
      submission.aiReport = aiAnalysis;
      await api.submitAssessment(submission);
      onComplete(submission);
      setStep('completed');
    }
  };

  return (
    <div className="min-h-screen bg-bgLight flex items-center justify-center py-16 px-6">
      <div className="max-w-4xl w-full">
        <AnimatePresence mode="wait">
          {step === 'level-select' && (
            <motion.div key="ls" initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="text-center space-y-12">
              <div className="space-y-4">
                <span className="text-gold text-[10px] font-bold uppercase tracking-[0.4em]">Section 01</span>
                <h2 className="text-4xl md:text-5xl font-serif text-navy">Module Selection</h2>
                <p className="text-slate max-w-lg mx-auto leading-relaxed">Please select the assessment unit corresponding to the subject's current academic tier.</p>
              </div>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {Object.values(WellBeingLevel).map(level => (
                  <button 
                    key={level} 
                    onClick={() => { setSelectedLevel(level); setStep('student-info'); }} 
                    className="p-10 border border-gray-100 bg-white rounded-2xl text-left hover:border-clinical hover:shadow-premium transition-all flex justify-between items-center group"
                  >
                    <div>
                      <span className="text-xl font-bold text-navy block tracking-tight">{level}</span>
                      <span className="text-[10px] font-bold text-slate uppercase tracking-widest mt-1 block opacity-60">Authorized Module</span>
                    </div>
                    <span className="w-8 h-8 rounded-full bg-gray-50 flex items-center justify-center text-navy group-hover:bg-clinical group-hover:text-white transition-all">→</span>
                  </button>
                ))}
              </div>
            </motion.div>
          )}

          {step === 'student-info' && (
            <motion.div key="si" initial={{ opacity: 0, scale: 0.98 }} animate={{ opacity: 1, scale: 1 }} exit={{ opacity: 0 }} className="max-w-xl mx-auto space-y-12">
              <div className="text-center space-y-4">
                <span className="text-gold text-[10px] font-bold uppercase tracking-[0.4em]">Section 02</span>
                <h2 className="text-4xl font-serif text-navy">Subject Intake Form</h2>
              </div>
              <form onSubmit={e => { e.preventDefault(); setStep('questions'); }} className="space-y-6 bg-white p-10 rounded-3xl border border-gray-100 shadow-premium">
                <div className="space-y-2">
                  <label className="text-[10px] font-bold uppercase text-slate tracking-widest ml-1">Full Legal Name</label>
                  <input required placeholder="As per official records" className="w-full px-6 py-4 rounded-xl bg-gray-50 border border-gray-100 focus:bg-white focus:border-clinical outline-none font-semibold text-navy transition-all" onChange={e => setStudentInfo({...studentInfo, name: e.target.value})} />
                </div>
                <div className="grid grid-cols-2 gap-6">
                  <div className="space-y-2">
                    <label className="text-[10px] font-bold uppercase text-slate tracking-widest ml-1">Standard/Class</label>
                    <input required placeholder="Current Tier" className="w-full px-6 py-4 rounded-xl bg-gray-50 border border-gray-100 focus:bg-white focus:border-clinical outline-none font-semibold text-navy transition-all" onChange={e => setStudentInfo({...studentInfo, standard: e.target.value})} />
                  </div>
                  <div className="space-y-2">
