                <button type="submit" className="w-full bg-navy text-white font-bold py-5 rounded-xl uppercase tracking-widest text-[11px] hover:bg-clinical transition-all shadow-premium mt-4">Begin Assessment Phase</button>
              </form>
            </motion.div>
          )}

          {step === 'questions' && (
            <motion.div key="q" initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="space-y-12">
              <div className="flex flex-col md:flex-row items-center justify-between gap-6 border-b border-gray-100 pb-8">
                <div>
                  <div className="inline-flex items-center space-x-2 bg-blue-50 px-3 py-1 rounded-full mb-2">
                    <span className="w-1.5 h-1.5 rounded-full bg-clinical" />
                    <span className="text-[9px] font-bold text-clinical uppercase tracking-widest">{selectedLevel} Module</span>
                  </div>
                  <h3 className="text-3xl font-serif text-navy">Question {currentQuestionIndex + 1} of {filteredQuestions.length}</h3>
                </div>
                <div className="w-full md:w-64 space-y-2 text-right">
                  <p className="text-[9px] font-bold text-slate uppercase tracking-widest">Progress: {progress}%</p>
                  <div className="h-1 bg-gray-100 rounded-full overflow-hidden">
                    <motion.div initial={{ width: 0 }} animate={{ width: `${progress}%` }} className="h-full bg-clinical" />
                  </div>
                </div>
              </div>

              <div className="py-8 space-y-6 text-center md:text-left">
                <h2 className="text-4xl font-serif text-navy leading-tight tracking-tight uppercase">
                  {filteredQuestions[currentQuestionIndex].textEn}
                </h2>
                <h3 className="text-3xl font-hindi font-bold text-clinical leading-snug">
                  {filteredQuestions[currentQuestionIndex].textHi}
                </h3>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {filteredQuestions[currentQuestionIndex].options.map(opt => (
                  <button 
                    key={opt.id} 
                    onClick={() => setTempOption(opt)}
                    className={`p-10 text-left border rounded-2xl transition-all flex items-start space-x-6 ${tempOption?.id === opt.id ? 'border-clinical bg-blue-50/30 ring-4 ring-clinical/5' : 'border-gray-100 bg-white hover:border-gray-300'}`}
