                    <h4 className="text-xl font-bold text-navy mb-1 uppercase tracking-tight">
                      {lvl.title}
                    </h4>
                    <p className="text-slate font-hindi text-lg mb-8 italic">
                      {lvl.hindi}
                    </p>
                    <p className="text-[10px] text-slate/50 font-bold uppercase tracking-widest leading-relaxed">
                      {lvl.desc}
                    </p>
                  </motion.div>
                ))}
              </div>
