              <div className="max-w-7xl mx-auto px-6 flex flex-wrap justify-center items-center gap-12 md:gap-32 text-center">
                <div>
                  <p className="text-gold text-4xl font-bold mb-2">99%</p>
                  <p className="text-white/40 text-[9px] font-bold uppercase tracking-widest">Clinical Accuracy</p>
                </div>
                <div className="w-px h-12 bg-white/10 hidden md:block" />
                <div>
                  <p className="text-gold text-4xl font-bold mb-2">Nit Patna</p>
                  <p className="text-white/40 text-[9px] font-bold uppercase tracking-widest">Incubation Node</p>
