                  {filteredQuestions[currentQuestionIndex].textEn}
                </h2>
                <h3 className="text-3xl font-hindi font-bold text-clinical leading-snug">
                  {filteredQuestions[currentQuestionIndex].textHi}
                </h3>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-16">
                {filteredQuestions[currentQuestionIndex].options.map(opt => (
                  <button 
                    key={opt.id} 
                    onClick={() => setTempOption(opt)}
                    className={`p-10 text-left border-2 rounded-2xl transition-all flex items-center space-x-6 ${tempOption?.id === opt.id ? 'border-navy bg-slate-50' : 'border-slate-50 hover:border-slate-200'}`}
                  >
                    <span className={`w-8 h-8 rounded-lg flex items-center justify-center font-bold text-[10px] ${tempOption?.id === opt.id ? 'bg-navy text-white' : 'bg-slate-100 text-slate/40'}`}>
                      {opt.id.toUpperCase()}
                    </span>
