                      <p className="font-bold text-navy uppercase tracking-tight leading-none mb-1">{opt.en}</p>
                      <p className="text-slate font-hindi text-sm opacity-60">{opt.hi}</p>
                    </div>
                  </button>
                ))}
              </div>

              <div className="flex justify-center">
                 <button 
                   disabled={!tempOption}
                   onClick={handleNext}
                   className={`px-24 py-6 rounded-xl font-bold uppercase tracking-widest text-[11px] transition-all shadow-premium ${tempOption ? 'bg-navy text-white' : 'bg-slate-100 text-slate/20'}`}
                 >
                   {currentQuestionIndex === filteredQuestions.length - 1 ? 'Finalize Case File' : 'Confirm Choice'}
                 </button>
              </div>
            </motion.div>
          )}

          {step === 'syncing' && (
            <div className="text-center py-20">
              <div className="w-12 h-12 border-2 border-slate-100 border-t-navy rounded-full animate-spin mx-auto mb-8" />
              <h2 className="text-xl font-bold uppercase tracking-widest text-navy">Synchronizing Records</h2>
              <p className="text-xs font-bold text-slate/40 uppercase tracking-[0.2em] mt-3">Encrypting indicators for NitGyanam Institutional Node</p>
            </div>
          )}

          {step === 'completed' && (
            <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="text-center max-w-2xl mx-auto space-y-10">
              <div className="w-20 h-20 bg-emerald-50 text-emerald-500 rounded-full flex items-center justify-center text-4xl mx-auto shadow-inner">✓</div>
              <h2 className="text-5xl font-bold text-navy tracking-tight uppercase">Session Secure</h2>
              <p className="text-slate text-lg leading-relaxed font-light">
