          </button>
        </div>

        <AnimatePresence>
          {isMenuOpen && (
            <motion.div 
              initial={{ opacity: 0, y: -20 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: -20 }}
              className="absolute top-full left-0 right-0 bg-white border-b border-slate-100 p-10 flex flex-col space-y-6 shadow-premium md:hidden"
            >
              <button onClick={() => { onNavigate('home'); setIsMenuOpen(false); }} className="text-2xl font-bold text-navy uppercase tracking-tighter text-left">Home</button>
              <button onClick={() => { onNavigate('quiz'); setIsMenuOpen(false); }} className="text-2xl font-bold text-navy uppercase tracking-tighter text-left">Wellness Check</button>
              {user ? (
                 <>
                  <button onClick={() => { onNavigate('dashboard'); setIsMenuOpen(false); }} className="text-2xl font-bold text-clinical uppercase tracking-tighter text-left">Insights Portal</button>
                  <button onClick={() => { onLogout(); setIsMenuOpen(false); }} className="text-2xl font-bold text-red-500 uppercase tracking-tighter text-left">Sign Out</button>
                 </>
              ) : (
                 <button onClick={() => { onNavigate('login'); setIsMenuOpen(false); }} className="text-2xl font-bold text-navy uppercase tracking-tighter text-left">Faculty Access</button>
              )}
            </motion.div>
          )}
        </AnimatePresence>
      </nav>

      <main className="flex-grow pt-20 md:pt-24">
        {children}
      </main>

      <Footer />
    </div>
  );
};

