import React, { useState, useMemo, useEffect } from 'react';
import { WellBeingLevel, Question, ResponseIndicator, StudentInfo, Submission, Option } from '../types';
import { api } from '../services/api';
import { motion, AnimatePresence } from 'framer-motion';

interface QuizProps {
  onComplete: (submission: Submission) => void;
}

type QuizStep = 'level-select' | 'student-info' | 'questions' | 'completed' | 'syncing';

const Quiz: React.FC<QuizProps> = ({ onComplete }) => {
  const [step, setStep] = useState<QuizStep>('level-select');
  const [questions, setQuestions] = useState<Question[]>([]);
  const [selectedLevel, setSelectedLevel] = useState<WellBeingLevel | null>(null);
  const [studentInfo, setStudentInfo] = useState<StudentInfo>({ name: '', age: '', standard: '', school: '' });
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [answers, setAnswers] = useState<{ [id: string]: { indicator: ResponseIndicator; optionId: string } }>({});
  const [tempOption, setTempOption] = useState<Option | null>(null);

  useEffect(() => {
    const load = async () => {
      const qData = await api.fetchQuestions();
      setQuestions(qData);
    };
    load();
  }, []);

  const filteredQuestions = useMemo(() => {
    return questions.filter(q => q.level === selectedLevel);
  }, [selectedLevel, questions]);

  const progress = filteredQuestions.length > 0 
    ? Math.round(((currentQuestionIndex) / filteredQuestions.length) * 100) 
    : 0;

  const handleNext = async () => {
    if (!tempOption) return;
    const questionId = filteredQuestions[currentQuestionIndex].id;
    const newAnswers = { ...answers, [questionId]: { indicator: tempOption.indicator, optionId: tempOption.id } };
    setAnswers(newAnswers);
    setTempOption(null);

    if (currentQuestionIndex < filteredQuestions.length - 1) {
      setCurrentQuestionIndex(prev => prev + 1);
    } else {
      setStep('syncing');
      const answerList = Object.values(newAnswers).map(a => a.indicator);
      const { riskStatus, conclusion } = api.analyzeResults(answerList);

      const submission: Submission = {
        id: `NIT-${Math.random().toString(36).substr(2, 6).toUpperCase()}`,
        student: studentInfo,
        level: selectedLevel!,
        answers: newAnswers,
        metrics: {
          healthyCount: answerList.filter(v => v === ResponseIndicator.HEALTHY).length,
          concernCount: answerList.filter(v => v === ResponseIndicator.CONCERN).length,
          redFlagCount: answerList.filter(v => v === ResponseIndicator.RED_FLAG).length,
          totalQuestions: answerList.length
        },
        riskStatus,
        conclusion,
        timestamp: Date.now(),
      };

      const aiAnalysis = await api.generateAIAnalysis(submission, questions);
      submission.aiReport = aiAnalysis;
      await api.submitAssessment(submission);
      onComplete(submission);
      setStep('completed');
    }
  };

  return (
    <div className="min-h-screen bg-white flex items-center justify-center py-24 px-6">
      <div className="max-w-4xl w-full">
        <AnimatePresence mode="wait">
          {step === 'level-select' && (
            <motion.div key="ls" initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="text-center">
              <span className="text-gold text-[10px] font-bold uppercase tracking-[0.4em] mb-4 block">Discovery Stage 01</span>
              <h2 className="text-4xl md:text-5xl font-serif text-navy mb-12 tracking-tight">Academic Path Selection</h2>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-5 text-left">
                {Object.values(WellBeingLevel).map(level => (
                  <button 
                    key={level} 
                    onClick={() => { setSelectedLevel(level); setStep('student-info'); }} 
                    className="p-10 border border-slate-100 bg-slate-50 hover:bg-white hover:border-navy hover:shadow-premium rounded-[2.5rem] transition-all flex justify-between items-center group"
                  >
                    <div>
                      <span className="text-xl font-bold text-navy block tracking-tighter">{level}</span>
                      <span className="text-[9px] font-bold text-slate/40 uppercase tracking-widest mt-1 block">Support Module</span>
                    </div>
                    <span className="w-10 h-10 rounded-full bg-slate-100 flex items-center justify-center text-navy group-hover:bg-clinical group-hover:text-white transition-all">→</span>
                  </button>
                ))}
              </div>
            </motion.div>
          )}

          {step === 'student-info' && (
            <motion.div key="si" initial={{ opacity: 0, scale: 0.98 }} animate={{ opacity: 1, scale: 1 }} exit={{ opacity: 0 }} className="max-w-xl mx-auto">
              <div className="text-center mb-12">
                <span className="text-gold text-[10px] font-bold uppercase tracking-[0.4em] mb-4 block">Discovery Stage 02</span>
                <h2 className="text-4xl font-serif text-navy tracking-tight">Tell us about yourself</h2>
              </div>
              <form onSubmit={e => { e.preventDefault(); setStep('questions'); }} className="space-y-6">
                <div className="space-y-2">
                   <label className="text-[10px] font-bold uppercase text-slate tracking-widest px-2">Your Name</label>
                   <input required placeholder="Student Name" className="w-full px-8 py-5 rounded-2xl bg-slate-50 border border-slate-200 outline-none focus:border-navy focus:bg-white transition-all font-semibold shadow-sm" onChange={e => setStudentInfo({...studentInfo, name: e.target.value})} />
                </div>
                <div className="grid grid-cols-2 gap-6">
                  <div className="space-y-2">
                     <label className="text-[10px] font-bold uppercase text-slate tracking-widest px-2">Grade</label>
                     <input required placeholder="Standard" className="w-full px-8 py-5 rounded-2xl bg-slate-50 border border-slate-200 outline-none focus:border-navy focus:bg-white transition-all font-semibold shadow-sm" onChange={e => setStudentInfo({...studentInfo, standard: e.target.value})} />
                  </div>
                  <div className="space-y-2">
                     <label className="text-[10px] font-bold uppercase text-slate tracking-widest px-2">Age</label>
                     <input required type="number" placeholder="Years" className="w-full px-8 py-5 rounded-2xl bg-slate-50 border border-slate-200 outline-none focus:border-navy focus:bg-white transition-all font-semibold shadow-sm" onChange={e => setStudentInfo({...studentInfo, age: e.target.value})} />
                  </div>
                </div>
                <div className="space-y-2">
                   <label className="text-[10px] font-bold uppercase text-slate tracking-widest px-2">Institution</label>
                   <input required placeholder="School Name" className="w-full px-8 py-5 rounded-2xl bg-slate-50 border border-slate-200 outline-none focus:border-navy focus:bg-white transition-all font-semibold shadow-sm" onChange={e => setStudentInfo({...studentInfo, school: e.target.value})} />
                </div>
                <button type="submit" className="w-full bg-navy text-white font-bold py-6 rounded-2xl uppercase tracking-widest text-[11px] hover:bg-clinical transition-all shadow-premium mt-6">Enter Discovery Path</button>
              </form>
            </motion.div>
          )}

          {step === 'questions' && (
            <motion.div key="q" initial={{ opacity: 0 }} animate={{ opacity: 1 }}>
              <div className="mb-16 flex flex-col md:flex-row items-center justify-between gap-10 border-b border-slate-100 pb-12">
                <div className="text-center md:text-left">
                  <p className="text-[10px] font-bold text-gold uppercase tracking-[0.4em] mb-2">{selectedLevel} • Step {currentQuestionIndex + 1}</p>
                  <h3 className="text-3xl font-serif text-navy uppercase tracking-tighter">Wellness Check-in</h3>
                </div>
                <div className="w-full md:w-72">
                   <div className="flex justify-between text-[10px] font-bold uppercase tracking-widest mb-3 text-slate/30">
                     <span>Path Progress</span>
                     <span>{progress}%</span>
                   </div>
                   <div className="h-1.5 bg-slate-100 rounded-full overflow-hidden">
                     <motion.div 
                        initial={{ width: 0 }}
                        animate={{ width: `${progress}%` }}
                        className="h-full bg-navy" 
                     />
                   </div>
                </div>
              </div>

              <div className="mb-20 space-y-8">
                <h2 className="text-4xl md:text-5xl font-serif text-navy leading-tight tracking-tight uppercase">
                  {filteredQuestions[currentQuestionIndex].textEn}
                </h2>
                <h3 className="text-3xl font-hindi font-bold text-clinical leading-snug">
                  {filteredQuestions[currentQuestionIndex].textHi}
                </h3>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-5 mb-20">
                {filteredQuestions[currentQuestionIndex].options.map(opt => (
                  <button 
                    key={opt.id} 
                    onClick={() => setTempOption(opt)}
                    className={`p-10 text-left border-2 rounded-[2.5rem] transition-all flex items-center space-x-8 ${tempOption?.id === opt.id ? 'border-navy bg-slate-50 shadow-inner-soft' : 'border-slate-50 bg-white hover:border-slate-200 shadow-sm'}`}
                  >
                    <span className={`w-10 h-10 rounded-xl flex items-center justify-center font-bold text-xs shrink-0 transition-colors ${tempOption?.id === opt.id ? 'bg-navy text-white' : 'bg-slate-100 text-slate/30'}`}>
                      {opt.id.toUpperCase()}
                    </span>
                    <div>
                      <p className="font-bold text-navy uppercase tracking-tight leading-none mb-2">{opt.en}</p>
                      <p className="text-slate/60 font-hindi text-sm italic">{opt.hi}</p>
                    </div>
                  </button>
                ))}
              </div>

              <div className="flex justify-center">
                 <button 
                   disabled={!tempOption}
                   onClick={handleNext}
                   className={`px-24 py-6 rounded-2xl font-bold uppercase tracking-widest text-[11px] transition-all shadow-premium ${tempOption ? 'bg-navy text-white' : 'bg-slate-100 text-slate/20'}`}
                 >
                   {currentQuestionIndex === filteredQuestions.length - 1 ? 'Save Record' : 'Confirm Choice'}
                 </button>
              </div>
            </motion.div>
          )}

          {step === 'syncing' && (
            <div className="text-center py-24 space-y-10">
              <div className="w-16 h-16 border-2 border-slate-100 border-t-navy rounded-full animate-spin mx-auto" />
              <div className="space-y-4">
                <h2 className="text-2xl font-bold uppercase tracking-widest text-navy tracking-[0.2em]">Processing Insights</h2>
                <p className="text-[10px] font-bold text-slate/40 uppercase tracking-[0.3em]">Synchronizing with NitGyanam Institutional Node</p>
              </div>
            </div>
          )}

          {step === 'completed' && (
            <motion.div initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }} className="text-center max-w-2xl mx-auto space-y-12">
              <div className="w-24 h-24 bg-emerald-50 text-emerald-500 rounded-full flex items-center justify-center text-4xl mx-auto shadow-inner-soft ring-1 ring-emerald-100">✓</div>
              <div className="space-y-6">
                <h2 className="text-5xl font-serif text-navy tracking-tight uppercase">Journey Saved</h2>
                <p className="text-slate text-lg leading-relaxed font-light">
                  Your wellness record has been securely archived. These supportive insights will assist mentors in providing the best environment for your academic growth.
                </p>
              </div>
              <button 
                onClick={() => window.location.reload()}
                className="px-16 py-6 bg-navy text-white font-bold rounded-2xl uppercase tracking-widest text-[11px] shadow-premium hover:bg-clinical"
              >
                Return to Entrance
              </button>
            </motion.div>
          )}
        </AnimatePresence>
      </div>
    </div>
  );
};

