  const [activeView, setActiveView] = useState<AppView>('home');
  const [user, setUser] = useState<User | null>(null);

  useEffect(() => {
    const savedUser = localStorage.getItem('ng_user_session');
    if (savedUser) setUser(JSON.parse(savedUser));
  }, []);

  const handleLogin = (u: User) => {
    setUser(u);
    localStorage.setItem('ng_user_session', JSON.stringify(u));
    setActiveView('dashboard');
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('ng_user_session');
    setActiveView('home');
  };

  const levels = [
    { title: WellBeingLevel.LEVEL_1, hindi: 'कक्षा १ से ३', icon: '✦', desc: 'Foundational Discovery' },
    { title: WellBeingLevel.LEVEL_2, hindi: 'कक्षा ४ से ६', icon: '✧', desc: 'Resilience Mapping' },
    { title: WellBeingLevel.LEVEL_3, hindi: 'कक्षा ७ से ८', icon: '✸', desc: 'Social Connection Path' },
    { title: WellBeingLevel.LEVEL_4, hindi: 'कक्षा ९ से १०', icon: '✹', desc: 'Aspirational Wellness' },
  ];

  const renderContent = () => {
    switch (activeView) {
      case 'home':
        return (
          <div className="pb-32 bg-bgLight">
            <Hero 
              onStartQuiz={() => setActiveView('quiz')} 
              onLogin={() => setActiveView('login')} 
