                  <span className="text-clinical text-[10px] font-bold uppercase tracking-[0.4em] block mb-4 underline underline-offset-8 decoration-gold/50">Support Architecture</span>
                  <h3 className="text-4xl md:text-5xl font-serif text-navy leading-[1.1]">
