import React, { useState, useEffect } from 'react';
import { Question, WellBeingLevel, ResponseIndicator } from '../types';
import { api } from '../services/api';

const QuestionManager: React.FC = () => {
  const [questions, setQuestions] = useState<Question[]>([]);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [formData, setFormData] = useState<Partial<Question>>({});

  useEffect(() => {
    const loadData = async () => {
      const data = await api.fetchQuestions();
      setQuestions(data);
    };
    loadData();
  }, []);

  const handleSave = () => {
    let updated;
    if (editingId === 'new') {
      const newQ: Question = {
        ...formData as Question,
        id: `support_${Date.now()}`,
      };
      updated = [...questions, newQ];
    } else {
      updated = questions.map(q => q.id === editingId ? { ...q, ...formData } : q);
    }
    setQuestions(updated);
    api.saveQuestions(updated);
    setEditingId(null);
  };

  const deleteQuestion = (id: string) => {
    if (confirm('Are you sure you want to delete this academic support question?')) {
      const updated = questions.filter(q => q.id !== id);
      setQuestions(updated);
      api.saveQuestions(updated);
    }
  };

  const openEditor = (q?: Question) => {
    if (q) {
      setEditingId(q.id);
      setFormData(q);
    } else {
      setEditingId('new');
      setFormData({
        level: WellBeingLevel.LEVEL_1,
        textEn: '',
        textHi: '',
        options: [
          { id: 'a', en: '', hi: '', indicator: ResponseIndicator.HEALTHY },
          { id: 'b', en: '', hi: '', indicator: ResponseIndicator.HEALTHY },
          { id: 'c', en: '', hi: '', indicator: ResponseIndicator.CONCERN },
          { id: 'd', en: '', hi: '', indicator: ResponseIndicator.RED_FLAG },
        ]
      });
    }
  };

  return (
    <div className="max-w-7xl mx-auto px-6 py-20 bg-bgLight">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-16 gap-6">
        <div>
          <h2 className="text-4xl font-serif text-navy tracking-tight">Academic Inventory</h2>
          <p className="text-slate/60 text-lg font-light">Bilingual Wellness Discovery Bank</p>
        </div>
        <button 
          onClick={() => openEditor()}
          className="bg-navy text-white px-10 py-4 rounded-2xl font-bold uppercase tracking-widest text-[10px] hover:bg-clinical transition-all shadow-premium"
        >
          + Add Discovery Entry
        </button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        {questions.map(q => (
          <div key={q.id} className="bg-white border border-slate-100 rounded-[3rem] p-10 shadow-premium group hover:border-navy transition-all flex flex-col justify-between">
            <div>
              <div className="flex items-center space-x-3 mb-6">
                <span className="text-[9px] font-bold bg-gold/10 text-gold px-3 py-1 rounded-full uppercase tracking-widest">{q.level}</span>
                <span className="text-[9px] font-bold text-slate/30 uppercase tracking-[0.2em]">{q.id}</span>
              </div>
              <h4 className="font-bold text-2xl text-navy leading-tight mb-4">{q.textEn}</h4>
              <p className="text-slate/60 font-hindi text-xl italic leading-relaxed">{q.textHi}</p>
            </div>
            <div className="flex justify-end space-x-6 mt-10 pt-8 border-t border-slate-50">
              <button onClick={() => openEditor(q)} className="text-[10px] font-bold text-navy uppercase tracking-widest hover:text-clinical transition-all">Modify</button>
              <button onClick={() => deleteQuestion(q.id)} className="text-[10px] font-bold text-red-400 uppercase tracking-widest hover:text-red-600 transition-all">Remove</button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default QuestionManager;

