    { title: WellBeingLevel.LEVEL_3, hindi: 'कक्षा ७ से ८', icon: '✸', desc: 'Identity & Connection' },
    { title: WellBeingLevel.LEVEL_4, hindi: 'कक्षा ९ से १०', icon: '✹', desc: 'Future Aspirations' },
  ];

  const renderContent = () => {
    switch (activeView) {
      case 'home':
        return (
          <div className="pb-32 bg-bgLight">
            <Hero 
              onStartQuiz={() => setActiveView('quiz')} 
              onLogin={() => setActiveView('login')} 
            />

            <section className="max-w-7xl mx-auto px-6 py-40">
              <div className="flex flex-col lg:flex-row items-end justify-between mb-24 gap-12 text-center lg:text-left">
