                  <h3 className="text-4xl md:text-5xl font-serif text-navy leading-[1.1]">
                    Structured for <br />
                    <span className="italic text-gold">Compassionate</span> Guidance.
                  </h3>
                </div>
                <p className="text-slate text-lg max-w-sm font-light italic opacity-60 mx-auto lg:mx-0">
                  "Understanding oneself is the primary driver of academic and personal achievement."
                </p>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
                {levels.map((lvl, i) => (
                  <motion.div
                    key={i}
                    whileHover={{ y: -8 }}
                    onClick={() => setActiveView('quiz')}
                    className="group bg-white p-12 rounded-[3.5rem] cursor-pointer shadow-premium border border-slate-100 transition-all hover:border-navy"
