                    <h4 className="text-xl font-bold text-navy mb-1 uppercase tracking-tight">
                      {lvl.title}
                    </h4>
                    <p className="text-slate font-hindi text-xl mb-8 opacity-80 group-hover:opacity-100">
                      {lvl.hindi}
                    </p>
                    <p className="text-[10px] text-slate/40 font-bold uppercase tracking-widest leading-relaxed">
                      {lvl.desc}
                    </p>
                  </motion.div>
                ))}
              </div>
            </section>

            <section className="bg-navy py-24 relative overflow-hidden">
               <div className="absolute top-0 right-0 w-96 h-96 bg-clinical/10 blur-[100px] rounded-full -translate-y-1/2 translate-x-1/2" />
               <div className="max-w-7xl mx-auto px-6 text-center">
                  <div className="grid grid-cols-1 md:grid-cols-3 gap-16 md:gap-8 items-center">
                    <div className="space-y-2">
                       <p className="text-gold text-5xl font-serif">Incubated</p>
                       <p className="text-white/30 text-[10px] font-bold uppercase tracking-[0.4em]">NIT PATNA Node</p>
                    </div>
                    <div className="space-y-2">
                       <p className="text-gold text-5xl font-serif">Recognized</p>
                       <p className="text-white/30 text-[10px] font-bold uppercase tracking-[0.4em]">DPIIT | Startup Bihar</p>
                    </div>
                    <div className="space-y-2">
                       <p className="text-gold text-5xl font-serif">Verified</p>
                       <p className="text-white/30 text-[10px] font-bold uppercase tracking-[0.4em]">Institutional Path v2.9</p>
                    </div>
                  </div>
               </div>
            </section>
          </div>
        );
      case 'quiz':
        return <Quiz onComplete={() => setActiveView('home')} />;
      case 'login':
        return <Auth onLogin={handleLogin} />;
